INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (2642, 254162, 'tt0356148', NULL, 'Twenty Something Taipei', '台北晚9朝5', 'movie', 2002, 'https://image.tmdb.org/t/p/w500/A43djfTIdiphl3NHZfnESdi7vRQ.jpg', NULL, 'In the Taiwanese capital of Taipei, the taboo of sex is racing through everyone''s minds: a kindergarten teacher is a party animal at night, a sex-addicted hairstylist seduces anyone she can, a cyber angel hungers for various sexual relationships, and a lesbian swears to protect the women of the world. In their lives the questions of sex, love, and the game of romance plays through their minds, but will the answers ever come?', NULL, NULL, 0.4514, 4.292, 0, 1.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (2643, 999075, 'tt27722618', NULL, 'Left-Handed Girl', '左撇子女孩', 'movie', 2025, 'https://image.tmdb.org/t/p/w500/hfuxIKRCNsecLmoDdO0HJ1YUvv1.jpg', 'https://image.tmdb.org/t/p/original/xqft4oJyMATznCFFLpTlQPiSr8N.jpg', 'A mother and her two daughters move to Taipei to open a noodle stand at a vibrant night market, but family secrets and tradition test their fresh start.', NULL, NULL, 1.3998, 7.282, 0, 1.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (2644, 10451, 'tt0111797', NULL, 'Eat Drink Man Woman', '飲食男女', 'movie', 1994, 'https://image.tmdb.org/t/p/w500/olhIWtIBFg6VWK59DEd4lAvgVgz.jpg', 'https://image.tmdb.org/t/p/original/tllmUjmEQKF0OaH7FgqZYnLBsYB.jpg', 'Retired and widowed Chinese master chef Chu lives in modern day Taipei, with his three attractive daughters, all of whom are unattached. Soon, each daughter encounters a new man in their lives. When these new relationships blossom, stereotypes are broken and the living situation within the family changes.', NULL, NULL, 1.0773, 7.606, 0, 2.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (2645, 47008, 'tt1882928', NULL, 'Midnight Diner', '深夜食堂', 'tv', 2009, 'https://image.tmdb.org/t/p/w500/Aou5vJF5kvHRFp7IZILwK0ZO2sB.jpg', 'https://image.tmdb.org/t/p/original/oPLhHWou5HEB5dhbI2ZFuYQlSKw.jpg', 'Set in a small restaurant in the corner of a shopping district. The unusual eatery is only open after midnight, and its standard menu consists of just a single choice. However, the customers still come for the amusing chatter and the proprietor''s willingness to cook any dish that they request. This drama depicts the lives of the restaurant''s patrons, including a yakuza, an unsuccessful actor, a group of office ladies, a newspaper delivery boy, and a stripper.', NULL, NULL, 3.4812, 8.2, 0, 1.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (2646, 26005, 'tt0123328', NULL, 'Made in Hong Kong', '香港製造', 'movie', 1997, 'https://image.tmdb.org/t/p/w500/gWuB0NcEyZu2oz1ppdIwNGUpZJe.jpg', 'https://image.tmdb.org/t/p/original/mXpB1O5M5dZBGKyCXL5F82dwZ58.jpg', 'After his father abandons the family, Autumn Moon drops out of high school and becomes a debt collector for the Triads. On his rounds, he meets and falls in love with Ping, a daughter of one of the Triads'' clients. She is suffering from a fatal kidney disease, and to pay for her medical expenses, Autumn Moon takes an assassination contract, but as he slips deeper into the criminal underworld, he''s haunted by a figure from his past.', NULL, NULL, 0.9681, 7.6, 0, 1.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (2647, 78450, 'tt0091355', NULL, 'Terrorizers', '恐怖份子', 'movie', 1986, 'https://image.tmdb.org/t/p/w500/7uX1PVn9Tob81hqwdzAjqPeaXZO.jpg', 'https://image.tmdb.org/t/p/original/vooAbSV1zJqwRNHxCxFQ8fVDm38.jpg', 'An uncompromising look into urban life from the eyes of a voyeuristic photographer, a rebellious teenager, and a married couple teetering on the edge of adultery.', NULL, NULL, 1.5661, 7.4, 0, 1.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (2648, 475149, 'tt7010412', NULL, 'The Great Buddha+', '大佛普拉斯', 'movie', 2017, 'https://image.tmdb.org/t/p/w500/hUVHENyEicvL25aaC03xnCk0XTs.jpg', 'https://image.tmdb.org/t/p/original/bwDPtZ2UOQqS2L6TPXoNRlCMF5o.jpg', 'Security guard Pickle and his trash collector friend Belly Button kill time together in night shifts watching the American-educated boss''s dash-cam recordings of his various sexual encounters with women. Against the buddies'' will, something horrifying rather than erotic reveals.', NULL, NULL, 1.003, 7.917, 0, 1.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (2649, 307081, 'tt1798684', NULL, 'Southpaw', 'Southpaw', 'movie', 2015, 'https://image.tmdb.org/t/p/w500/kSQ49Fi3NVTqGGXILmxV2T2pdkG.jpg', 'https://image.tmdb.org/t/p/original/zT9iYKMtmU82Jo44WbiuMOW7jRi.jpg', 'Billy "The Great" Hope, the reigning junior middleweight boxing champion, has an impressive career, a loving wife and daughter, and a lavish lifestyle. However, when tragedy strikes, Billy hits rock bottom, losing his family, his house and his manager. He soon finds an unlikely savior in Tick Willis, a former fighter who trains the city''s toughest amateur boxers. With his future on the line, Hope fights to reclaim the trust of those he loves the most.', NULL, NULL, 4.1439, 7.363, 0, 2.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
