INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (2651, 2758, 'tt0106220', NULL, 'Addams Family Values', 'Addams Family Values', 'movie', 1993, 'https://image.tmdb.org/t/p/w500/sdxT2VjVSx9DRicwnuECUdBHeE7.jpg', 'https://image.tmdb.org/t/p/original/sZhTfYouKM1iV3rVbgIVEQFQogA.jpg', 'Siblings Wednesday and Pugsley Addams will stop at nothing to get rid of Pubert, the new baby boy adored by parents Gomez and Morticia. Things go from bad to worse when the new "black widow" nanny, Debbie Jellinsky, launches her plan to add Fester to her collection of dead husbands.', NULL, NULL, 3.5257, 6.978, 0, 9.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (2652, 26258, 'tt0112602', NULL, 'Bushwhacked', 'Bushwhacked', 'movie', 1995, 'https://image.tmdb.org/t/p/w500/j3H0POtvl0Tt4Meesvp7HX6JxAv.jpg', 'https://image.tmdb.org/t/p/original/fyy4NAy6D9AdGomxGdtdg7vrQex.jpg', 'A inept courier realises he has been used by criminals to deliver money. On the run from both the criminals and police, he poses as a Scout leader and leads a scout group on a hike through the mountains.', NULL, NULL, 0.4768, 5.395, 0, 11.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (2653, 11821, 'tt0101745', NULL, 'Doc Hollywood', 'Doc Hollywood', 'movie', 1991, 'https://image.tmdb.org/t/p/w500/36yGVgFWg7PvDdZ10Csg1uHpcZd.jpg', 'https://image.tmdb.org/t/p/original/9Vp4761sywoBOdHOjGN1a6pFk61.jpg', 'After leaving Washington D.C. hospital, plastic surgeon Ben Stone heads for California, where a lucrative practice in Beverly Hills awaits. After a car accident, he''s sentenced to perform as the community''s general practitioner.', NULL, NULL, 0.9315, 6.365, 0, 11.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (2654, 10398, 'tt0150377', NULL, 'Double Jeopardy', 'Double Jeopardy', 'movie', 1999, 'https://image.tmdb.org/t/p/w500/dPd9QvEeMQpgHO6iLB1LqALTZl.jpg', 'https://image.tmdb.org/t/p/original/fk4NXhazfRKtQaVEV9IPeM7OIVH.jpg', 'Libby Parsons, wrongly convicted of her husband Nick''s murder, thinks he is still alive. She survives the long years in prison with two burning desires sustaining her -- finding her son and solving the mystery that destroyed her once-happy life. Standing between her and her quest, however, is her parole officer, Travis Lehman. Libby poses a challenge to the cynical officer, one that forces him to face up to his own failings while pitting him against his superior and law enforcement colleagues, as she plunges into a desperate fight for justice, survival, and revenge.', NULL, NULL, 2.3045, 6.64, 0, 11.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (2655, 18935, 'tt0092974', NULL, 'Ernest Goes to Camp', 'Ernest Goes to Camp', 'movie', 1987, 'https://image.tmdb.org/t/p/w500/14GzgM3U2ABJ3h4ixhOkWpoQJAj.jpg', 'https://image.tmdb.org/t/p/original/hBew3uipRuqCcxQYFJcdaY2Upeu.jpg', 'Ernest, a lovable loser who works as a summer camp handyman and dreams of becoming a guidance counselor, must find a way to inspire a group of juvenile delinquents while stopping a shady strip mining company from closing the camp as well.', NULL, NULL, 1.381, 5.251, 0, 11.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (2656, 295699, 'tt2937696', NULL, 'Everybody Wants Some!!', 'Everybody Wants Some!!', 'movie', 2016, 'https://image.tmdb.org/t/p/w500/vAIFZ8bw0spSvcIYgfuX99B3H2w.jpg', 'https://image.tmdb.org/t/p/original/31M4Rty4wAeRqVuykwJqTKIh0Ed.jpg', 'A comedy that follows a group of friends as they navigate their way through the freedoms and responsibilities of unsupervised adulthood.', NULL, NULL, 1.5329, 6.38, 0, 11.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (2657, 14819, 'tt0110006', NULL, 'Heavyweights', 'Heavyweights', 'movie', 1995, 'https://image.tmdb.org/t/p/w500/uN65XQzyPknLZs2R6koZ2Cu6eGC.jpg', 'https://image.tmdb.org/t/p/original/hBUgtysIiuvJite0NX0C0FHJ90m.jpg', 'Camp Hope is a summer retreat for overweight boys run by a kindly couple who make the campers feel comfortable with their extra pounds. But when tyrannical fitness guru Tony buys the camp, he puts the kids on a cruel regimen that goes too far. Sick of the endless weeks of "all work and no play," the kids stage a coup and reclaim their summer of fun.', NULL, NULL, 0.898, 6.192, 0, 11.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (2658, 33506, 'tt0107212', NULL, 'Indian Summer', 'Indian Summer', 'movie', 1993, 'https://image.tmdb.org/t/p/w500/A1gUvZbQ25wsnj7HD8bDwTxOSWy.jpg', 'https://image.tmdb.org/t/p/original/4ZRyBQI9clbKxb9rsCqJkXdRIut.jpg', 'A group of childhood friends, now in their thirties, reunite at Camp Tamakwa. Only a few of the original campers show up, but they still have a good time reminiscing. The people share experiences and grow while at the camp. They are dismayed to discover that the camp''s owner, Unca Lou, is going to close the camp down.', NULL, NULL, 0.7241, 6.277, 0, 6.33333333333333303e+00, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (2659, 33689, 'tt0113442', NULL, 'It Takes Two', 'It Takes Two', 'movie', 1995, 'https://image.tmdb.org/t/p/w500/4CptjFLiIJXtjc3dykS7vkEHMbw.jpg', 'https://image.tmdb.org/t/p/original/yS3E5LOcFsk3eWGh3oWGnsfV1M8.jpg', 'Identical 9-year-olds from very different backgrounds: orphaned Amanda and wealthy Alyssa meet at summer camp and decide to switch places -- and play matchmaker between Alyssa''s dad, Roger, and the kind social worker who cares for Amanda.', NULL, NULL, 1.5881, 6.504, 0, 7.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (2660, 7095, 'tt0116669', NULL, 'Jack', 'Jack', 'movie', 1996, 'https://image.tmdb.org/t/p/w500/9ZklgGqTljzg9VxzumbVOC1UKAs.jpg', 'https://image.tmdb.org/t/p/original/v9wC8Rf3RHYQ6yKO4yQAlQLHSA6.jpg', 'Born with a rare condition that makes him age four times faster than normal, ten-year-old Jack Powell looks like a forty-year-old man. After years of homeschooling, he enters public school for the first time, eager to make friends and live like any other kid—only to discover that growing up too fast means learning some of life’s hardest lessons early.', NULL, NULL, 1.7973, 6.295, 0, 11.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (2661, 19087, 'tt0104670', NULL, 'Ladybugs', 'Ladybugs', 'movie', 1992, 'https://image.tmdb.org/t/p/w500/gC0DmdJu7rHaqYjyXeo8GLLJ2Oa.jpg', 'https://image.tmdb.org/t/p/original/awY6dPWIrtR919DZCITOmvq3dSU.jpg', 'To climb the corporate ladder to success, a businessman agrees to coach his company''s all-girl soccer team with the help of his secret weapon: his fiancee''s son.', NULL, NULL, 1.0674, 5.6, 0, 11.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (2662, 24962, 'tt0113737', NULL, 'Magic in the Water', 'Magic in the Water', 'movie', 1995, 'https://image.tmdb.org/t/p/w500/54BiiZRiIUFDNboO8RZ81AKqk3d.jpg', 'https://image.tmdb.org/t/p/original/sG5V7eXUmaylQlDkVsEdpErPGEE.jpg', 'Radio psychologist Jack Black takes his children Joshua and Ashley on a ''vacation'' to a lake in British Columbia. While he grinds away at work the children discover that the famous local lake monster "Orky" may not be just a gimmick to attract tourists after all. In fact, Orky may enable them to get closer to their workaholic dad, and help stop local polluters who are dumping toxic waste.', NULL, NULL, 0.6099, 5.3, 0, 11.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (2663, 40490, 'tt0113755', NULL, 'Man of the House', 'Man of the House', 'movie', 1995, 'https://image.tmdb.org/t/p/w500/6bnOhhrrrq6RZhMgz4aGyqbJ9Wf.jpg', 'https://image.tmdb.org/t/p/original/45XjLWOACuD9UcFZ5iFGtQPVlAW.jpg', 'Ben Archer is not happy. His mother, Sandy, has just met a man, and it looks like things are pretty serious. Driven by a fear of abandonment, Ben tries anything and everything to ruin the "love bubble" which surrounds his mom. However, after Ben and Jack''s experiences in the Indian Guides, the two become much closer.', NULL, NULL, 0.629, 5.4, 0, 11.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (2664, 14035, 'tt0079540', NULL, 'Meatballs', 'Meatballs', 'movie', 1979, 'https://image.tmdb.org/t/p/w500/9YA2erSNcca9NWd0xePC9ArFWnx.jpg', 'https://image.tmdb.org/t/p/original/rHVRERTgJT8SDuuhOW81gpaTg4I.jpg', 'Tripper is the head counselor at a budget summer camp called Camp Northstar. In truth, he''s young at heart and only marginally more mature than the campers themselves. Tripper befriends Rudy, a loner camper who has trouble fitting in. As Tripper inspires his young charges to defeat rival Camp Mohawk in the annual Olympiad competition, Rudy plays matchmaker between Tripper and Roxanne, a female counselor at Northstar.', NULL, NULL, 2.8696, 5.829, 0, 9.66666666666666607e+00, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
