INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (2668, 81367, 'tt0120213', NULL, 'Slappy and the Stinkers', 'Slappy and the Stinkers', 'movie', 1998, 'https://image.tmdb.org/t/p/w500/g6PsNLXH5bS8ZuPmhXujcM0JTHx.jpg', 'https://image.tmdb.org/t/p/original/sfBHEZAxIiaIQ6QOd85R3IPrg59.jpg', 'Five 2nd-grade kids who don''t follow strict rules by their school principal Brinway are dubbed "Stinkers" by him. On the class visit to an aquarium the Stinkers decide that a sea lion called Slappy doesn''t feel too good there, "free" him, and plant him into Brinway''s hot-tub.', NULL, NULL, 1.3423, 5.4, 0, 11.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
