INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (2670, 77945, 'tt0146315', NULL, 'Tom''s Midnight Garden', 'Tom''s Midnight Garden', 'movie', 1999, 'https://image.tmdb.org/t/p/w500/9flBPLbXqiU6VyDsYUvF9Lp4c4H.jpg', 'https://image.tmdb.org/t/p/original/ahaW7C6kjdy1dkldx08KQgUhpNw.jpg', 'When Tom''s brother Peter gets measles, he is sent to stay with his Uncle Alan and Aunt Gwen in a flat with no garden and an elderly landlady, Mrs Bartholomew, living upstairs. Because he may be infectious, he is not allowed to play outside and feels lonely. Without exercise he is less sleepy at night and when he hears the communal grandfather clock strangely strike 13, he investigates and finds the small back yard is now a large sunlit garden.', NULL, NULL, 0.8224, 6.071, 0, 11.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
