INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (2681, 558, 'tt0316654', NULL, 'Spider-Man 2', 'Spider-Man 2', 'movie', 2004, 'https://image.tmdb.org/t/p/w500/aGuvNAaaZuWXYQQ6N2v7DeuP6mB.jpg', 'https://image.tmdb.org/t/p/original/6al048Lat3eLVQOuKtc9h6Tu94d.jpg', 'Peter Parker is going through a major identity crisis. Burned out from being Spider-Man, he decides to shelve his superhero alter ego, which leaves the city suffering in the wake of carnage left by the evil Doc Ock. In the meantime, Parker still can''t act on his feelings for Mary Jane Watson, a girl he''s loved since childhood. A certain anger begins to brew in his best friend Harry Osborn as well...', NULL, NULL, 5.0366, 7.315, 0, 1.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
