INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (2713, 87093, 'tt1126590', NULL, 'Big Eyes', 'Big Eyes', 'movie', 2014, 'https://image.tmdb.org/t/p/w500/203HAjJcLMl7xThcTqZx4zmEGcV.jpg', 'https://image.tmdb.org/t/p/original/qis71iUABx2eTxN9FzOnLbnJ2OA.jpg', 'In the late 1950s and early ''60s, artist Walter Keane achieves unbelievable fame and success with portraits of saucer-eyed waifs. However, no one realizes that his wife, Margaret, is the real painter behind the brush. Although Margaret is horrified to learn that Walter is passing off her work as his own, she is too meek to protest too loudly. It isn''t until the Keanes'' marriage comes to an end and a lawsuit follows that the truth finally comes to light.', NULL, NULL, 2.3208, 6.968, 0, 9.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (2714, 38810, 'tt1379182', NULL, 'Dogtooth', 'Κυνόδοντας', 'movie', 2009, 'https://image.tmdb.org/t/p/w500/cBrhzHcOxXclTItkPzsJUCTSFyl.jpg', 'https://image.tmdb.org/t/p/original/b9g6LwxptKxoMqBtxrQqBml4vMb.jpg', 'Three teenagers are confined to an isolated country estate that could very well be on another planet. The trio spend their days listening to endless homemade tapes that teach them a whole new vocabulary. Any word that comes from beyond their family abode is instantly assigned a new meaning. Hence ''the sea'' refers to a large armchair and ''zombies'' are little yellow flowers. Having invented a brother whom they claim to have ostracized for his disobedience, the uber-controlling parents terrorize their offspring into submission.', NULL, NULL, 2.0258, 7.039, 0, 11.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
