INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (2804, 804413, 'tt14813212', NULL, 'The Munsters', 'The Munsters', 'movie', 2022, 'https://image.tmdb.org/t/p/w500/kJaEVFhDouD72GKANMkYqzQky9n.jpg', 'https://image.tmdb.org/t/p/original/tCuqvnWOAGhpkz8fpN8748EN4Ri.jpg', 'Lily is a typical 150-year-old lovelorn vampire who''s looking for the man of her nightmares -- until she lays her eyes on Herman, a 7-foot-tall green experiment with a heart of gold. It''s love at first shock as these two ghouls fall fangs over feet for each other in a Transylvanian romance. Unfortunately, it''s not all smooth sailing in the cemetery as Lily''s father has other plans for his beloved daughter''s future, and they don''t involve her new bumbling beau.', NULL, NULL, 1.223, 5.583, 0, 9.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
