INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (2820, 2264, 'tt0082671', NULL, 'Lola', 'Lola', 'movie', 1981, 'https://image.tmdb.org/t/p/w500/rZqgDP5kRqh2eaPj5uLzYEbWz40.jpg', 'https://image.tmdb.org/t/p/original/bJd8rcyl6hAt6nDbEFhrxKlBrNJ.jpg', 'Germany in the autumn of 1957: Lola, a seductive cabaret singer-prostitute exults in her power as a temptress of men, but she wants out—she wants money, property, and love. Pitting a corrupt building contractor against the new straight-arrow building commissioner, Lola launches an outrageous plan to elevate herself in a world where everything, and everyone, is for sale. Shot in childlike candy colors, Fassbinder’s homage to Josef von Sternberg’s classic The Blue Angel stands as a satiric tribute to capitalism.', NULL, NULL, 1.8338, 6.919, 0, 9.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (2821, 42135, 'tt0084565', NULL, 'Querelle', 'Querelle', 'movie', 1982, 'https://image.tmdb.org/t/p/w500/7rakWIm1EeXvmInWljMqugxBqK2.jpg', 'https://image.tmdb.org/t/p/original/cINtl1Bh47Ut4NhwLokLHQXgre0.jpg', 'French sailor Querelle arrives in Brest and starts frequenting a strange whorehouse. He discovers that his brother Robert is the lover of the lady owner, Lysiane. Here, you can play dice with Nono, Lysiane''s husband: if you win, you are allowed to make love with Lysiane; if you lose, you have to make love with Nono... Querelle loses on purpose.', NULL, NULL, 1.0484, 6.611, 0, 9.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
