INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (2831, NULL, NULL, 11409, 'Submerged', 'Submerged', 'game', 2015, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1tjn.jpg', NULL, 'Submerged is a third-person combat-free game in which you explore a mysterious flooded city and discover the beauty of desolation in vast outdoor environments. You take on the role of Miku, a young girl who has brought her wounded brother to the city in their small fishing boat. Navigate the flooded city streets by boat, scale the drowned buildings, and use your telescope to scour the city for the supplies needed to save your dying sibling. As you explore the city at your own pace, you encounter the habitat that flourishes in this colorful place and discover hidden objects that piece together the story of a broken world and a broken family.', 'https://www.igdb.com/games/submerged', '["PlayStation 4", "PC (Microsoft Windows)", "iOS", "Xbox One", "Nintendo Switch"]', NULL, NULL, 0, 1.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (2832, NULL, NULL, 11156, 'Horizon Zero Dawn', 'Horizon Zero Dawn', 'game', 2017, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2una.jpg', NULL, 'Welcome to a vibrant world rich with the beauty of nature – but inhabited by awe-inspiring, highly advanced machines. As a young machine hunter named Aloy, you must unravel the mysteries of this world and find your own destiny.', 'https://www.igdb.com/games/horizon-zero-dawn', '["PlayStation 4", "PC (Microsoft Windows)", "PlayStation 5"]', NULL, NULL, 0, 1.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (2833, NULL, NULL, 18137, 'Dark Earth', 'Dark Earth', 'game', 1997, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2j6j.jpg', NULL, 'Dark Earth is a post-apocalyptic action-adventure game for the PC.

Dark Earth takes place several centuries in the future, when a meteor collision with Earth tossed up great clouds of dust that blocked out the sun. Earth''s remaining survivors began to seek refuge beneath small openings in the clouds, the few places light could be found. Those that remained in the ''dark earth'' were hunted by strange creatures, infected with the darkness.

To shelter themselves from the dangerous ''dark earth'', the people began to form cities beneath the light called ''Stallites''. At the time of the game, most of the citizens of the stallite have forgotten their history and now worship the light as a god. The stalites are run by ''Sun Priests'', who maintain order and prevent the creatures of darkness from harming the city. The game follows the story of Arkhan, a "guardian of fire", protector of the stallite ''Sparta'' and the Sun Priests.

After an attack on the sun priests, Arkhan has a poison thrown into his face that begins to infect him with the dark sickness. He begins to mutate into a creature of the dark and has to find a cure before his transformation is complete. Along the way, he is treated as an enemy by most of his former friends while he struggles to uncover the conspiracy behind the attack.', 'https://www.igdb.com/games/dark-earth', '["PC (Microsoft Windows)"]', NULL, NULL, 0, 1.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
