INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (2846, 43376, 'tt0042619', NULL, 'Diary of a Country Priest', 'Journal d''un curé de campagne', 'movie', 1951, 'https://image.tmdb.org/t/p/w500/mft7ZJqHxUyFaLL3ZYXX1MN2Gro.jpg', 'https://image.tmdb.org/t/p/original/luytZGyalDVIBy2jDk51EKV45T8.jpg', 'An inexperienced, sickly priest shows up in the rural French community of Ambricourt, where he joins the community''s clergy. But the locals don''t take kindly to the priest, and his ascetic ways and unsociable demeanor make him an outcast. During Bible studies at the nearby girls school, he is continually mocked by his students. Then his attempt to intervene in a family feud backfires into a scandal. His failures, compounded with his declining health, begin to erode his faith.', NULL, NULL, 0.4728, 7.484, 0, 10.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
