INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (2872, 8468, 'tt0102035', NULL, 'Highway 61', 'Highway 61', 'movie', 1991, 'https://image.tmdb.org/t/p/w500/kUJNsyvl3yezjbWuQG2Mh7HtPmc.jpg', 'https://image.tmdb.org/t/p/original/zIZ3EB1dsZGPrw75T4TopDGpgCM.jpg', 'A naive Canadian barber who knows US popular culture inside and out meets a flamboyant roadie who needs someone to drive her and her "brother''s" corpse from Thunder Bay, Ontario to New Orleans. Chaos ensues after the barber agrees to drive her, the corpse, and the drugs stashed within all the way.', NULL, NULL, 0.4605, 6.818, 0, 1.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
