INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (2874, 19255, 'tt1176740', NULL, 'Away We Go', 'Away We Go', 'movie', 2009, 'https://image.tmdb.org/t/p/w500/zWxjopWXpnC1vSbnO7mw2URna22.jpg', 'https://image.tmdb.org/t/p/original/rSEZ4e8rWCk9SsRvuwyxtLLUV0w.jpg', 'Verona and Burt have moved to Colorado to be close to Burt''s parents but, with Verona expecting their first child, Burt''s parents inexplicably decide to move to Belgium, now leaving them in a place they hate and without a support structure in place. They set off on a whirlwind tour of of disparate locations where they have friends or relatives, sampling not only different cities and climates but also different families. Along the way they realize that the journey is less about discovering where they want to live and more about figuring out what type of parents they want to be.', NULL, NULL, 0.9013, 6.661, 0, 6.5, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (2875, 59468, 'tt1441912', NULL, 'The Way', 'The Way', 'movie', 2010, 'https://image.tmdb.org/t/p/w500/uaRfG7n92IiuYcKLl7LJo2gr6qO.jpg', 'https://image.tmdb.org/t/p/original/xqOcH6cKhGEbzgypAHU6UlUUDrh.jpg', 'When his son dies while hiking the famed Camino de Santiago pilgrimage route in the Pyrenees, Tom flies to France to claim the remains. Looking for insights into his estranged child’s life, he decides to complete the 500-mile mountain trek to Spain. Tom soon joins up with other travelers and realizes they’re all searching for something.', NULL, NULL, 1.3521, 7.103, 0, 1.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (2876, 309304, 'tt4270516', NULL, 'Grandma', 'Grandma', 'movie', 2015, 'https://image.tmdb.org/t/p/w500/4LW20TF4NfQgHj5rZs0d0cgxRjV.jpg', 'https://image.tmdb.org/t/p/original/kiVn09vghnscMWMqlX8uoQuXtMW.jpg', 'Self-described misanthrope Elle Reid has her protective bubble burst when her 18-year-old granddaughter, Sage, shows up needing help. The two of them go on a day-long journey that causes Elle to come to terms with her past and Sage to confront her future.', NULL, NULL, 1.0154, 6.437, 0, 1.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (2877, 89237, 'tt2139843', NULL, 'Electrick Children', 'Electrick Children', 'movie', 2012, 'https://image.tmdb.org/t/p/w500/lWszypKqAt91GFtRP2HyUP6UdOq.jpg', 'https://image.tmdb.org/t/p/original/cMNQMG3lqBIgbGgEgolm2jc1djB.jpg', 'Rachel is a rambunctious girl from a polygamist colony in southern Utah. On Rachel’s 15th birthday, she finds a forbidden cassette tape. Having never seen anything like it before, Rachel plays the cassette tape, and finds glorious rock & roll thereupon. Weeks later, Rachel realizes a miracle has occurred - and the cassette tape must have something to do with it. She leaves her family and runs away to the closest city: Las Vegas. There she searches for the singer of the band on the cassette tape.', NULL, NULL, 1.3243, 6.4, 0, 1.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (2878, 88005, 'tt1307068', NULL, 'Seeking a Friend for the End of the World', 'Seeking a Friend for the End of the World', 'movie', 2012, 'https://image.tmdb.org/t/p/w500/rBbCwFLyt7Q25yaw2bEOQh7RMG1.jpg', 'https://image.tmdb.org/t/p/original/tEJ3nvnp520AvNPbhCegHMo1EfM.jpg', 'As an asteroid nears Earth, a man finds himself alone after his wife leaves in a panic. He decides to take a road trip to reunite with his high school sweetheart. Accompanying him is a neighbor who inadvertently puts a wrench in his plan.', NULL, NULL, 2.3133, 6.565, 0, 1.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (2879, 419635, 'tt1880399', NULL, 'Kodachrome', 'Kodachrome', 'movie', 2017, 'https://image.tmdb.org/t/p/w500/mseyc8v3UD1DhaZ3kSdXs4Dj9Xf.jpg', 'https://image.tmdb.org/t/p/original/mRnceZhq19AoJf97ueVX7lhAUl5.jpg', 'Matt Ryder is convinced to drive his estranged and dying father Benjamin Ryder cross country to deliver four old rolls of Kodachrome film to the last lab in the world that can develop them before it shuts down for good. Along with Ben''s nurse Zooey, the three navigate a world changing from analogue to digital while trying to put the past behind them.', NULL, NULL, 1.12, 6.797, 0, 1.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
