INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (2956, 847, 'tt0096446', NULL, 'Willow', 'Willow', 'movie', 1988, 'https://image.tmdb.org/t/p/w500/pAIRGMIdN7ZdZhflazdV2ezuJ9f.jpg', 'https://image.tmdb.org/t/p/original/3sF6AibdbTTkswfSRxXEGCt5w6s.jpg', 'The evil Queen Bavmorda hunts the newborn princess Elora Danan, a child prophesied to bring about her downfall. When the royal infant is found by Willow, a timid farmer and aspiring sorcerer, he''s entrusted with delivering her from evil.', NULL, NULL, 2.1366, 7.007, 0, 1.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (2957, 14135, 'tt0106341', NULL, 'Bad Boy Bubby', 'Bad Boy Bubby', 'movie', 1993, 'https://image.tmdb.org/t/p/w500/fERbcofifizJmDt892lFcrIYhFh.jpg', 'https://image.tmdb.org/t/p/original/ad6tCgBgKieGjIde9RasliPlCfY.jpg', 'Bad Boy Bubby is just that: a bad boy. So bad, in fact, that his mother has kept him locked in their house for his entire thirty years, convincing him that the air outside is poisonous. After a visit from his estranged father, circumstances force Bubby into the waiting world, a place which is just as unusual to him as he is to the world.', NULL, NULL, 1.3868, 6.916, 0, 10.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (2958, 59967, 'tt1276104', NULL, 'Looper', 'Looper', 'movie', 2012, 'https://image.tmdb.org/t/p/w500/sNjL6SqErDBE8OUZlrDLkexfsCj.jpg', 'https://image.tmdb.org/t/p/original/4GPCnwvTbsDleH5QIOyDLMsK8a2.jpg', 'In the year 2044, time travel has not yet been invented but in 30 years it will have been. When the mob wants to get rid of someone, they will send their target into the past where a looper, a hired gun, like Joe is waiting to mop up. Joe is getting rich and life is good until the day the mob decides to close the loop, sending back Joe''s future self for assassination.', NULL, NULL, 6.7314, 6.91, 0, 10.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (2959, 133694, 'tt2091473', NULL, 'Promised Land', 'Promised Land', 'movie', 2012, 'https://image.tmdb.org/t/p/w500/5C0b6Wu4Z0V4NuA1cD8SZU7FCkb.jpg', 'https://image.tmdb.org/t/p/original/pq0YbRUY7JMbuElDWIK6nRoFSdk.jpg', 'A salesman for a natural gas company experiences life-changing events after arriving in a small town, where his corporation wants to tap into the available resources.', NULL, NULL, 1.7262, 6.291, 0, 10.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (2960, 41841, 'tt0111359', NULL, 'Tall Tale: The Unbelievable Adventure', 'Tall Tale: The Unbelievable Adventure', 'movie', 1995, 'https://image.tmdb.org/t/p/w500/di43EvahPBbdTgZrBxx8yZjvFu8.jpg', 'https://image.tmdb.org/t/p/original/b6UiIu8YiFC2CXjMj7BCDVhKts0.jpg', 'A young boy draws on the inspiration of legendary western characters to find the strength to fight an evil land baron in the old west who wants to steal his family''s farm and destroy their idyllic community. When Daniel Hackett sees his father Jonas gravely wounded by the villainous Stiles, his first urge is for his family to flee the danger, and give up their life on a farm which Daniel has come to despise anyway. Going alone to a lake to try to decide what to do, he falls asleep on a boat and wakes to find himself in the wild west, in the company of such "tall tale" legends as Pecos Bill, Paul Bunyan, John Henry and Calamity Jane. Together, they battle the same villains Daniel is facing in his "real" world, ending with a heroic confrontation in which the boy stands up to Stiles and his henchmen, and rallies his neighbors to fight back against land grabbers who want to destroy their town.', NULL, NULL, 0.6707, 6.23, 0, 10.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (2961, 9609, 'tt0105046', NULL, 'Of Mice and Men', 'Of Mice and Men', 'movie', 1992, 'https://image.tmdb.org/t/p/w500/qAHLUMZyoW3iwj2b01B2nKcePTA.jpg', 'https://image.tmdb.org/t/p/original/5HVwz8cImMEwcV2z1SMFyJHY51q.jpg', 'Two drifters, one a gentle but slow giant, try to make money working the fields during the Depression so they can fulfill their dreams.', NULL, NULL, 1.4568, 7.256, 0, 10.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
