INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (2982, 613, 'tt0363163', NULL, 'Downfall', 'Der Untergang', 'movie', 2004, 'https://image.tmdb.org/t/p/w500/cP1ElGjBhbZAAqmueXjHDKlSwiP.jpg', 'https://image.tmdb.org/t/p/original/cmyrTgVrfsQNlQG4o6m7E5HoP0L.jpg', 'In April of 1945, Germany stands at the brink of defeat with the Russian Army closing in from the east and the Allied Expeditionary Force attacking from the west. In Berlin, capital of the Third Reich, Adolf Hitler proclaims that Germany will still achieve victory and orders his generals and advisers to fight to the last man. When the end finally does come, and Hitler lies dead by his own hand, what is left of his military must find a way to end the killing that is the Battle of Berlin, and lay down their arms in surrender.', NULL, NULL, 3.1861, 7.862, 0, 11.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (2983, 464768, 'tt6848928', NULL, 'Junk Head', 'JUNK HEAD', 'movie', 2022, 'https://image.tmdb.org/t/p/w500/t1pHIeZZGmr8TWMyn7r1TGoMnMo.jpg', 'https://image.tmdb.org/t/p/original/c3sfYdDKVpM9dyPeKgm980e3GRf.jpg', 'Mankind can no longer reproduce because of gene manipulation aimed at making life longer. The clones ruling the bottomless underworld may have become fertile. Parton is selected to go on a mission through a subterranean labyrinth crawling with monsters to secure humanity''s future.', NULL, NULL, 1.3891, 6.6, 0, 11.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (2984, NULL, NULL, 185258, 'ARC Raiders', 'ARC Raiders', 'game', 2025, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9rk1.jpg', NULL, 'ARC Raiders is a multiplayer extraction adventure, set in a lethal future earth, ravaged by a mysterious mechanized threat known as ARC. Enlist as a Raider and scavenge the surface to thrive in a desolate world. But beware of the machines. Beware of Raiders preying on others.

ARC Raiders blends the tension from extraction shooters with atmospheric settings from the adventure genre. Lurking threats—from deadly machines to other Raiders—create a constant ebb and flow of intensity, where every moment is charged with the thrill of high stakes. Extract valuable loot and explore the unfolding mysteries of a vibrant, lethal world.

ARC Raiders supports seamless social play across PlayStation, Xbox, and PC. Play with your squad and thrive as a team, or rise in the ranks as a lone ranger.', 'https://www.igdb.com/games/arc-raiders', '["Xbox Series X|S", "PC (Microsoft Windows)", "PlayStation 5"]', NULL, NULL, 0, 11.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (2985, NULL, NULL, 966, 'Resident Evil 3: Nemesis', 'Resident Evil 3: Nemesis', 'game', 1999, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2vvb.jpg', NULL, 'Resident Evil 3: Nemesis is a survival horror video game and the third instalment in the Resident Evil series. Like its two predecessors, it is a third-person action-adventure game with polygonal characters on pre-rendered backgrounds with cinematic camera angles. Although the game uses the same basic engine and gameplay as the previous games, the gameplay is improved by features such as auto-targeting, a 180-degree spin, and a new dodge move that allows Jill to avoid enemy attacks. The PC and Dreamcast versions include all eight of Jill''s possible costumes, as well as the mercenary mini-game Operation Mad Jackal, which allows players to play as one of the three Umbrella soldiers. On the PlayStation version, these special features must be unlocked by beating the game with a high score.', 'https://www.igdb.com/games/resident-evil-3-nemesis', '["PlayStation 3", "Nintendo GameCube", "PC (Microsoft Windows)", "PlayStation", "PlayStation Portable", "Dreamcast"]', NULL, NULL, 0, 11.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (2986, 245927, 'tt27444205', NULL, 'Paradise', 'Paradise', 'tv', 2025, 'https://image.tmdb.org/t/p/w500/l8RqfhqEk04W5sSOjQ9zeWU1DyM.jpg', 'https://image.tmdb.org/t/p/original/5QsLvWh8J1mXl1W05wNJknMmhzR.jpg', 'The tranquility in a serene, wealthy community inhabited by some of the world''s most prominent individuals explodes when a shocking murder occurs and a high stakes investigation unfolds.', NULL, NULL, 15.3847, 7.509, 0, 10.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
