INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (2991, 271397, 'tt1745787', NULL, 'The Tribe', 'Плем''я', 'movie', 2014, 'https://image.tmdb.org/t/p/w500/85gHJfR9aM3mRIHq6G5ateLGOeh.jpg', 'https://image.tmdb.org/t/p/original/pp6RHy8glYVte8DrSkaTyDDFHVs.jpg', 'Deaf-mute Sergey enters a specialized boarding school for the deaf. In navigating through the school''s hierarchy, he encounters a corrupt underbelly of criminality, known as The Tribe. By participating in several robberies, he gets propelled higher into the organization, when he meets one of the Chief’s concubines Anya, and unwittingly breaks all the unwritten rules of the group."', NULL, NULL, 1.9319, 6.688, 0, 1.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
