INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (2993, 549509, 'tt8999762', NULL, 'The Brutalist', 'The Brutalist', 'movie', 2024, 'https://image.tmdb.org/t/p/w500/vP7Yd6couiAaw9jgMd5cjMRj3hQ.jpg', 'https://image.tmdb.org/t/p/original/hmZnqijPaaACjenDkrbWcCmcADI.jpg', 'When an innovative modern architect flees post-war Europe, he is given the opportunity to rebuild his legacy. Set during the dawn of the modern United States (in Pennsylvania), his wife joins him, and their lives are forever changed by a demanding, wealthy patron.', NULL, NULL, 7.3377, 6.951, 0, 1.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (2994, 43738, 'tt1426361', NULL, 'Eastern Plays', 'Източни пиеси', 'movie', 2009, 'https://image.tmdb.org/t/p/w500/lmGgetgogDi9RPtlApf2zNYYxB9.jpg', 'https://image.tmdb.org/t/p/original/b9i6Z6RD8UI4SCtWCzPY1eVdCSP.jpg', 'Two estranged brothers are brought together when they have opposite roles in a racist beating: while Georgi who''s recently joined a neo-nazi group participates in the violence, Hristo witnesses and rescues a Turkish family. Only by reuniting will the two brothers be able to assess what they really want from life.', NULL, NULL, 2.8008, 6.443, 0, 1.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (2995, 42699, 'tt0092337', NULL, 'Dekalog', 'Dekalog', 'tv', 1989, 'https://image.tmdb.org/t/p/w500/v390wlQKSVpnuGuM3ynruH6PX7x.jpg', 'https://image.tmdb.org/t/p/original/6adZtyOer0YpMcxGD3ot52nIobb.jpg', 'The Ten Commandments, exact and uncompromising, literally cast in stone, continues to provide a source of moral conflict in contemporary society. In the ten part collection of films, The Decalogue, Krzysztof Kieslowski examines the dilemma of fundamental sin in the lives of ordinary Warsaw citizens.', NULL, NULL, 2.0345, 8.5, 0, 6.5, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (2996, 41914, 'tt0119608', NULL, 'Mandragora', 'Mandragora', 'movie', 1997, 'https://image.tmdb.org/t/p/w500/hlN6RBc5Xj4cVqKLTxl9LJp5MFi.jpg', 'https://image.tmdb.org/t/p/original/1nmYUfJCM2tUFqtDufcGBrq4pzU.jpg', 'Marek is a 15-year-old from a provincial village who runs away to Prague when he begins to fail at school. He is mugged shortly after arriving in the city and is rescued by Honza with the promise of work. Marek is taken to an apartment, drugged, and becomes a male prostitute. He is a bit smarter than his colleagues and teams up with a friend, David, in order to go after bigger scores – to cash in and get out. They manage to stash away a bit of money, but when it comes time to return home, Marek loses his nerve and is soon back in the city.', NULL, NULL, 1.2207, 5.803, 0, 1.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (2997, 34869, 'tt0847880', NULL, 'Cargo 200', 'Груз 200', 'movie', 2007, 'https://image.tmdb.org/t/p/w500/8F0vN9BNabjIO6edSlFe3RB7dCy.jpg', 'https://image.tmdb.org/t/p/original/dfViHCYAIEm3BVaCu1zk4GvugIg.jpg', 'While returning to Leningrad from a visit to his brother, Professor Artyom''s car breaks down and he finds assistance at an isolated farmhouse occupied by Alexey, his wife, a Vietnamese laborer, and a stranger who wanders around the farm. When his car is repaired, Artyom leaves, drunk on moonshine, and students Valera and Angelika arrive. After Valera gets drunk, the stranger abducts Angelika.', NULL, NULL, 1.118, 6.813, 0, 1.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (2998, 179246, 'tt2250564', NULL, 'In Bloom', 'In Bloom', 'movie', 2013, 'https://image.tmdb.org/t/p/w500/q6KMSzsHBtLYiBwXZDX9YMxsFQI.jpg', 'https://image.tmdb.org/t/p/original/n2goSFjKJ8fBbd1KdzVYALj7vz3.jpg', 'A portrayal of love and loss, In Bloom shows a personal and realistic tale of losing first love. During a tumultuous summer in Chicago, a serial killer terrorizes boystown while two young men experience the pain of separation and broken hearts.', NULL, NULL, 0.2886, 6.467, 0, 1.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (2999, 6077, 'tt0475169', NULL, '13 Tzameti', '13 Tzameti', 'movie', 2006, 'https://image.tmdb.org/t/p/w500/kSpFeY6ibND9ygqSFcOzEKK0Cl.jpg', 'https://image.tmdb.org/t/p/original/mmZvBvbAMPrDEJoP9YXUrRabQQz.jpg', 'Sebastian, a young man, has decided to follow instructions intended for someone else, without knowing where they will take him. Something else he does not know is that Gerard Dorez, a cop on a knife-edge, is tailing him. When he reaches his destination, Sebastian falls into a degenerate, clandestine world of mental chaos behind closed doors in which men gamble on the lives of others men.', NULL, NULL, 1.6834, 7.076, 0, 1.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3000, 46283, 'tt0407205', NULL, 'The Sisters', 'The Sisters', 'movie', 2005, 'https://image.tmdb.org/t/p/w500/5zhk4DhSwF8rATE4J7iZD05u1jd.jpg', 'https://image.tmdb.org/t/p/original/uG4BsZW7axw0qOf4Bj1dSYJ3X19.jpg', 'Based on Anton Chekov''s "The Three Sisters" about siblings living in a college town who struggle with the death of their father and try to reconcile relationships in their own lives.', NULL, NULL, 0.3799, 5.1, 0, 1.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3001, 5723, 'tt0907657', NULL, 'Once', 'Once', 'movie', 2007, 'https://image.tmdb.org/t/p/w500/7nW363kSYRCkr4VGOMvuSGwtzKs.jpg', 'https://image.tmdb.org/t/p/original/p1XSyBriqz7oBWoVcRqYlB6Kve3.jpg', 'A vacuum repairman moonlights as a street musician and hopes for his big break. One day a Czech immigrant, who earns a living selling flowers, approaches him with the news that she is also an aspiring singer-songwriter. The pair decide to collaborate, and the songs that they compose reflect the story of their blossoming love.', NULL, NULL, 1.7979, 7.428, 0, 1.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
