INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3004, 11489, 'tt0200071', NULL, 'Rosetta', 'Rosetta', 'movie', 1999, 'https://image.tmdb.org/t/p/w500/buwLjQPPA9FaATvKzeAppLXiGMB.jpg', 'https://image.tmdb.org/t/p/original/1ZBPashbl6CQ3IhfbM38A67tNnj.jpg', 'Young, impulsive Rosetta lives a hard and stressful life as she struggles to support herself and her alcoholic mother. Refusing all charity, she is desperate to maintain a dignified job.', NULL, NULL, 0.5767, 7.137, 0, 1.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3005, 6278, 'tt0253556', NULL, 'Reign of Fire', 'Reign of Fire', 'movie', 2002, 'https://image.tmdb.org/t/p/w500/vZVXCj3jXzIPJUHLaQohzt2uTM3.jpg', 'https://image.tmdb.org/t/p/original/gAozjuCvXYyrxhpkb0P4SuLnEkV.jpg', 'In post-apocalyptic England, an American volunteer and a British survivor team up to fight off a brood of fire-breathing dragons seeking to return to global dominance after centuries of rest underground. The Brit -- leading a clan of survivors to hunt down the King of the Dragons -- has much at stake: His mother was killed by a dragon, but his love is still alive.', NULL, NULL, 2.0307, 6.212, 0, 11.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3006, 80828, 'tt8697870', NULL, 'The Nevers', 'The Nevers', 'tv', 2021, 'https://image.tmdb.org/t/p/w500/v6Xmj8Fy7ZruVTz3y2Po7O0TQh4.jpg', 'https://image.tmdb.org/t/p/original/mhFYqrTLk5JlzzdHkyu4NVzasDj.jpg', 'In the last years of Victoria''s reign, London is beset by the "Touched": people — mostly women — who suddenly manifest abnormal abilities, some charming, some very disturbing. Among them are Amalia True, a mysterious, quick-fisted widow, and Penance Adair, a brilliant young inventor. They are the champions of this new underclass, making a home for the Touched, while fighting the forces of… well, pretty much all the forces — to make room for those whom history as we know it has no place.', NULL, NULL, 4.8192, 7.907, 0, 11.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3007, 90027, 'tt0489974', NULL, 'Carnival Row', 'Carnival Row', 'tv', 2019, 'https://image.tmdb.org/t/p/w500/jyhxT10e2z9IDsKoIQDKhyxSQJt.jpg', 'https://image.tmdb.org/t/p/original/7gfLuaqVBdtNxKIxp9uc8sOUlQg.jpg', 'In a mystical and dark city filled with humans, fairies and other creatures, a police detective investigates a series of gruesome murders leveled against the fairy population. During his investigation, the detective becomes the prime suspect and must find the real killer to clear his name.', NULL, NULL, 6.2061, 7.688, 0, 11.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3008, 98187, 'tt10893694', NULL, 'The Irregulars', 'The Irregulars', 'tv', 2021, 'https://image.tmdb.org/t/p/w500/qN6HCKR3ZRqbpGBWFctVlSTKR2k.jpg', 'https://image.tmdb.org/t/p/original/4sIjlFa2jn0SsWQVuTBEFgQy4eH.jpg', 'In Victorian London, a gang of troubled street teens are manipulated into solving crimes for the sinister Doctor Watson and his mysterious business partner, the elusive Sherlock Holmes. As the crimes take on a horrifying supernatural edge and a dark power emerges, it''ll be up to the Irregulars to come together to save not only London but the entire world.', NULL, NULL, 1.3995, 7.116, 0, 11.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3009, 27022, 'tt0963966', NULL, 'The Sorcerer''s Apprentice', 'The Sorcerer''s Apprentice', 'movie', 2010, 'https://image.tmdb.org/t/p/w500/b5pIUsGll0418NyfNA5eYCI9aoK.jpg', 'https://image.tmdb.org/t/p/original/mtrfLUfUoQunolDhmQy0GfbRclC.jpg', 'Balthazar Blake is a master sorcerer in modern-day Manhattan trying to defend the city from his arch-nemesis, Maxim Horvath. Balthazar can''t do it alone, so he recruits Dave Stutler, a seemingly average guy who demonstrates hidden potential, as his reluctant protégé. The sorcerer gives his unwilling accomplice a crash course in the art and science of magic, and together, these unlikely partners work to stop the forces of darkness.', NULL, NULL, 3.617, 6.146, 0, 14.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3010, 561, 'tt0360486', NULL, 'Constantine', 'Constantine', 'movie', 2005, 'https://image.tmdb.org/t/p/w500/vPYgvd2MwHlxTamAOjwVQp4qs1W.jpg', 'https://image.tmdb.org/t/p/original/x3YFn10ehQKMRIJwIfiDAX8S9Xt.jpg', 'John Constantine has literally been to Hell and back. When he teams up with a policewoman to solve the mysterious suicide of her twin sister, their investigation takes them through the world of demons and angels that exists beneath the landscape of contemporary Los Angeles.', NULL, NULL, 7.8109, 7.185, 0, 12.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3011, 123553, 'tt1538403', NULL, 'The Mortal Instruments: City of Bones', 'The Mortal Instruments: City of Bones', 'movie', 2013, 'https://image.tmdb.org/t/p/w500/zaK1aVn5vXfNwLIDop9U8XA3Q0x.jpg', 'https://image.tmdb.org/t/p/original/z4nKeZpPCrTifS6pzzK8vNleADl.jpg', 'In New York City, Clary Fray, a seemingly ordinary teenager, learns that she is descended from a line of Shadowhunters — half-angel warriors who protect humanity from evil forces. After her mother disappears, Clary joins forces with a group of Shadowhunters and enters Downworld, an alternate realm filled with demons, vampires, and a host of other creatures. Clary and her companions must find and protect an ancient cup that holds the key to her mother''s future.', NULL, NULL, 4.526, 6.424, 0, 11.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3012, 24869, 'tt1071804', NULL, 'Ink', 'Ink', 'movie', 2009, 'https://image.tmdb.org/t/p/w500/9vYyX7c8gZtxuqd6SiRukRb4gRd.jpg', 'https://image.tmdb.org/t/p/original/bDB9NAjkB1J7ab3lgydj75aLo7o.jpg', 'Invisible forces exert power over us in our sleep. A mercenary named Ink, on a literal nightmare mission, captures the spirit of 8-year-old Emma in the dream world. To save her, the dream-givers marshal all their resources, focusing on saving the soul of Emma''s tragically broken father.', NULL, NULL, 0.3865, 6.338, 0, 11.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3013, 127532, 'tt21209876', NULL, 'Solo Leveling', '俺だけレベルアップな件', 'tv', 2024, 'https://image.tmdb.org/t/p/w500/geCRueV3ElhRTr0xtJuEWJt6dJ1.jpg', 'https://image.tmdb.org/t/p/original/xMNH87maNLt9n2bMDYeI6db5VFm.jpg', 'They say whatever doesn’t kill you makes you stronger, but that’s not the case for the world’s weakest hunter Sung Jinwoo. After being brutally slaughtered by monsters in a high-ranking dungeon, Jinwoo came back with the System, a program only he could see, that’s leveling him up in every way. Now, he’s inspired to discover the secrets behind his powers and the dungeon that spawned them.', NULL, NULL, 24.2644, 8.669, 0, 11.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3014, 95479, 'tt12343534', NULL, 'JUJUTSU KAISEN', '呪術廻戦', 'tv', 2020, 'https://image.tmdb.org/t/p/w500/fHpKWq9ayzSk8nSwqRuaAUemRKh.jpg', 'https://image.tmdb.org/t/p/original/lthkKBLe1rX6iThgVFg22O02sJw.jpg', 'Yuji Itadori is a boy with tremendous physical strength, though he lives a completely ordinary high school life. One day, to save a classmate who has been attacked by curses, he eats the finger of Ryomen Sukuna, taking the curse into his own soul. From then on, he shares one body with Ryomen Sukuna. Guided by the most powerful of sorcerers, Satoru Gojo, Itadori is admitted to Tokyo Jujutsu High School, an organization that fights the curses... and thus begins the heroic tale of a boy who became a curse to exorcise a curse, a life from which he could never turn back.', NULL, NULL, 38.2296, 8.582, 0, 11.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3015, 4955, 'tt0486657', NULL, 'The Dresden Files', 'The Dresden Files', 'tv', 2007, 'https://image.tmdb.org/t/p/w500/rujRcP9fZAk7Sq0U8iDITOXouCW.jpg', 'https://image.tmdb.org/t/p/original/aVcchR91KUPU98JtWhnGcobnGgT.jpg', 'A Chicago-based wizard works as a private investigator.', NULL, NULL, 1.8193, 6.98, 0, 11.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
