INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3028, 15701, 'tt0267601', NULL, 'The Irrefutable Truth About Demons', 'The Irrefutable Truth About Demons', 'movie', 2000, 'https://image.tmdb.org/t/p/w500/oUDeAFislZ7xkCQn8VMt35nEtGz.jpg', 'https://image.tmdb.org/t/p/original/4dahYf4gDVvcw6NPjbCv8u6lRCK.jpg', 'In the place between what you know, and what you fear, demons rule. All hope is stripped away as demonic forces overcome you. Dr. Harry Ballard has just unearthed the essence of evil. He’s a marked man, a living sacrifice, thrown to the depths of the demon world. At his side is a beautiful young woman – an ex-cult member who’s experienced their immeasurable power.', NULL, NULL, 0.388, 5.2, 0, 11.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
