INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3030, 13418, 'tt0115288', NULL, 'Neverwhere', 'Neverwhere', 'tv', 1996, 'https://image.tmdb.org/t/p/w500/jQbTB9IhHQoqWrJs53iHI0f1c8F.jpg', 'https://image.tmdb.org/t/p/original/u9a0DbqejhqOIRpMwtbK1PZEOzU.jpg', 'Richard Mayhew leads an ordinary life in London when one day a girl named Door falls, injured, across his path. The next thing he knows, his life is gone and he''s pulled into the fantastical world of London Below. Pursued by the murderous Messrs. Croup and Vandemar, Door and Richard with the help of Hunter and the Marquis de Carabas, attempt to find the Angel Islington, who knows the secret behind the murder of Door''s family, and possibly a way for Richard to go home.', NULL, NULL, 1.1316, 6.661, 0, 12.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
