INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3075, 8851, 'tt0051418', NULL, 'The Blob', 'The Blob', 'movie', 1958, 'https://image.tmdb.org/t/p/w500/ctOwn1Ibg3SjDG4WulvFvSH0PRT.jpg', 'https://image.tmdb.org/t/p/original/32l2szM3oY7kdI3TMBral5dsc2E.jpg', 'A drive-in favorite, this sci-fi classic follows teenagers Steve and his best girl, Jane, as they try to protect their hometown from a gelatinous alien life form that engulfs everything it touches. The first to discover the substance and live to tell about it, Steve and Jane witness the blob destroying an elderly man, then it growing to a terrifying size. But no one else has seen the goo, and policeman Dave refuses to believe the kids without proof.', NULL, NULL, 0.8079, 6.2, 0, 2.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
