INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3081, 15096, 'tt0050084', NULL, '20 Million Miles to Earth', '20 Million Miles to Earth', 'movie', 1957, 'https://image.tmdb.org/t/p/w500/wozerDO9kpVBN63sq3wiM5zYmSo.jpg', 'https://image.tmdb.org/t/p/original/pvNE91iHqQlowSOwKHXgWV0gCaM.jpg', 'When the first manned flight to Venus returns to Earth, the rocket crash-lands in the Mediterranean near a small Italian fishing village. The locals manage to save one of the astronauts Colonel Calder, the mission commander. A young boy also recovers what turns out to be a specimen of an alien creature. Growing at a fantastic rate, it manages to escape and eventually threatens the city of Rome.', NULL, NULL, 0.552, 6.3, 0, 1.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
