INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3127, 1033148, 'tt9362736', NULL, 'Die My Love', 'Die My Love', 'movie', 2025, 'https://image.tmdb.org/t/p/w500/kajpShbFhOdpl6yCrLezMrr9tB4.jpg', 'https://image.tmdb.org/t/p/original/dEkFlZzj2cb5F7SShvqkL54E4lr.jpg', 'After inheriting a remote Montana house, Jackson moves there from New York with his partner Grace, and the couple soon welcome a child. As Jackson becomes increasingly absent and rural isolation sets in, Grace struggles with loneliness, creative frustration, and unresolved emotional wounds. What begins as an attempt at renewal gradually turns into an intense psychological descent, placing strain on their relationship and exposing the fragile balance between love, identity, and motherhood.', NULL, NULL, 3.611, 6.107, 0, 1.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3128, 393519, 'tt4954522', NULL, 'Raw', 'Grave', 'movie', 2017, 'https://image.tmdb.org/t/p/w500/kc8jT1MAiKM0iwdjAwC5lQrTNry.jpg', 'https://image.tmdb.org/t/p/original/46GikxYW84dRh71sWVY0eRQiHLX.jpg', 'Stringent vegetarian Justine encounters a decadent, merciless, and dangerously seductive world during her first week at veterinary school. Desperate to fit in, she strays from her principles and eats raw meat for the first time. She soon experiences terrible and unexpected consequences as her true self begins to emerge.', NULL, NULL, 4.8831, 7.025, 0, 1.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3129, 208277, 'tt2524674', NULL, 'Wetlands', 'Feuchtgebiete', 'movie', 2013, 'https://image.tmdb.org/t/p/w500/6hfZij2Nd8rCT1tezRkbzm7xWkl.jpg', 'https://image.tmdb.org/t/p/original/jqcILemNblXGIOeg9CDCzHEBEpc.jpg', 'Helen is a nonconformist teenage girl who maintains a conflictual relationship with her parents. Hanging out most of her time with her friend Corinna, with whom she breaks one social taboo after another, she uses sex as a way to rebel and break the conventional bourgeois ethic. After an intimate shaving accident, Helen ends up in the hospital where it doesn’t take long before she makes waves. But there she finds Robin, a male nurse who will sweep her off her feet...', NULL, NULL, 1.0173, 5.331, 0, 1.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3130, 589849, 'tt9867458', NULL, 'Muse', 'Muse', 'movie', 2019, 'https://image.tmdb.org/t/p/w500/utD20VNozhGw3zILsBnhNDrbJqz.jpg', NULL, 'Luca is the pre-eminent artist of his generation and at the peak of his career, lauded, feted and collected by all. He is the ultimate showman however, his fortune and fame have left him agoraphobic and crippled by depression. He hasn''t left his house in five years, he''s a virtual recluse who battles daily with his demon. When a chance encounter brings Luca back from the edge, the question is, can he stay there.', NULL, NULL, 1.2887, 0.0, 0, 1.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
