INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3136, 477044, 'tt6910282', NULL, 'Bergman Island', 'Bergman Island', 'movie', 2021, 'https://image.tmdb.org/t/p/w500/q8bQfC7SbaTDVKywhCiNL3ZVSyy.jpg', 'https://image.tmdb.org/t/p/original/e1X1veoQ5Hs45KoOjr80QMwVSgg.jpg', 'An English-German filmmaking couple retreat to Fårö for the summer to each write screenplays for their upcoming films in an act of pilgrimage to the place that inspired Ingmar Bergman. As the summer and their screenplays advance, the lines between reality and fiction start to blur against the backdrop of the Island''s wild landscape.', NULL, NULL, 1.4011, 6.261, 0, 1.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
