INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3138, 14347, 'tt0086973', NULL, 'Blame It on Rio', 'Blame It on Rio', 'movie', 1984, 'https://image.tmdb.org/t/p/w500/yzNtmqL6HUFC7FZl9DnGmhnCQUL.jpg', 'https://image.tmdb.org/t/p/original/zYeYZuqXuB2nfIR4zfKhaDWHeF6.jpg', 'Matthew Hollis is man on holiday in Rio with his best friend. Both men have teenage daughters with them. When Matthew falls for his best friend''s amorous daughter named Jennifer, they embark on a secret, if slightly one-sided relationship. Jennifer''s father is furious when he finds out about the ''older man'' in his daughter''s life, and sets out to hunt him down with the aid of Matthew!', NULL, NULL, 1.0259, 5.754, 0, 1.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3139, 10678, 'tt0305669', NULL, 'Bringing Down the House', 'Bringing Down the House', 'movie', 2003, 'https://image.tmdb.org/t/p/w500/jic0ULHTcqQQaCSIEw6SAhHhIPA.jpg', 'https://image.tmdb.org/t/p/original/mRaNy8rNfxOpT0LrD3FIQztmpYL.jpg', 'Uptight lawyer Peter Sanderson wants to dive back into dating after his divorce and has a hard time meeting the right women. He tries online dating and lucks out when he starts chatting with a fellow lawyer. The two agree to meet in the flesh, but the woman he meets — an escaped African-American convict named Charlene — is not what he expected. Peter is freaked out, but Charlene tries to convince him to take her case and prove her innocence. Along the way, she wreaks havoc on his middle-class life as he gets a lesson in learning to lighten up.', NULL, NULL, 0.9366, 6.0, 0, 1.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3140, 84184, 'tt1405365', NULL, 'Celeste & Jesse Forever', 'Celeste & Jesse Forever', 'movie', 2012, 'https://image.tmdb.org/t/p/w500/5Cr8kW7DjZEORU8jI32bqyHSGKW.jpg', 'https://image.tmdb.org/t/p/original/fKyKSmvxwMpT0qe6B0m2vbyzAOk.jpg', 'Celeste and Jesse met in high school and got married young. They laugh at the same jokes and finish each other’s sentences. They are forever linked in their friends’ minds as the perfect couple – she, a high-powered businesswoman and budding novelist; he, a free spirit who keeps things from getting boring. Their only problem is that they have decided to get divorced. Can their perfect relationship withstand this minor setback?', NULL, NULL, 2.0208, 6.4, 0, 1.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3141, 11216, 'tt0095765', NULL, 'Cinema Paradiso', 'Nuovo Cinema Paradiso', 'movie', 1988, 'https://image.tmdb.org/t/p/w500/gCI2AeMV4IHSewhJkzsur5MEp6R.jpg', 'https://image.tmdb.org/t/p/original/zoVeIgKzGJzpdG6Gwnr7iOYfIMU.jpg', 'A filmmaker recalls his childhood, when he fell in love with the movies at his village''s theater and formed a deep friendship with the theater''s projectionist.', NULL, NULL, 6.4431, 8.429, 0, 1.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3142, 10464, 'tt0109484', NULL, 'Corrina, Corrina', 'Corrina, Corrina', 'movie', 1994, 'https://image.tmdb.org/t/p/w500/atPbnSNt21aSysWOk4QCvRT5XxE.jpg', 'https://image.tmdb.org/t/p/original/rxRf5Te8PX4Ko5iFUN13llcsLI1.jpg', 'When Manny Singer''s wife dies, his young daughter Molly becomes mute and withdrawn. To help cope with looking after Molly, he hires sassy housekeeper Corrina Washington, who coaxes Molly out of her shell and shows father and daughter a whole new way of life. Manny and Corrina''s friendship delights Molly and enrages the other townspeople.', NULL, NULL, 0.9064, 6.7, 0, 1.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
