INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3173, 10590, 'tt0277434', NULL, 'We Were Soldiers', 'We Were Soldiers', 'movie', 2002, 'https://image.tmdb.org/t/p/w500/q2LeLzw4q9HTelkKx29dyTMf5zK.jpg', 'https://image.tmdb.org/t/p/original/30vLkH3xmWw1gcVN8ZyykWAauZT.jpg', 'The year is 1965 and America is at war with North Vietnam.  Commanding the air cavalry is Lt. Col. Hal Moore (Gibson), a born leader committed to his troops.  His target: the Ia Drang Valley, called "The Valley of Death."  As Moore prepares for one of the most violent battles in U.S. history, he delivers a stirring promise to his soldiers and their families: "I will leave no man behind...dead or alive.  We will all come home together."', NULL, NULL, 2.328, 7.133, 0, 2.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
