INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3219, 2163, 'tt0118771', NULL, 'Breakdown', 'Breakdown', 'movie', 1997, 'https://image.tmdb.org/t/p/w500/m3VB59ppr1RlpxNUYRUfZTgjgU.jpg', 'https://image.tmdb.org/t/p/original/e86x1nXqfXRlqATuy60MmzFUFQr.jpg', 'On their cross-country drive, a married couple, Jeff and Amy Taylor, experience car trouble after their SUV breaks down. Stranded in the New Mexico desert, the two catch a break when a passing truck driver offers Amy a ride to a nearby café to call for help. Meanwhile, Jeff is able to fix the car and make his way to the café, but Amy isn''t there. He tracks down the trucker ― who tells the police he''s never seen Jeff or his wife before. Jeff then begins a desperate, frenzied search for Amy.', NULL, NULL, 1.5066, 6.942, 0, 1.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
