INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3221, 212778, 'tt2883512', NULL, 'Chef', 'Chef', 'movie', 2014, 'https://image.tmdb.org/t/p/w500/hyp8EXDmO4dSC8V6Q5jU7gD1kcg.jpg', 'https://image.tmdb.org/t/p/original/igVNCpS132rOqrnDsrVYW5HCIsM.jpg', 'When Chef Carl Casper suddenly quits his job at a prominent Los Angeles restaurant after refusing to compromise his creative integrity for its controlling owner, he is left to figure out what''s next. Finding himself in Miami, he teams up with his ex-wife, his friend and his son to launch a food truck. Taking to the road, Chef Carl goes back to his roots to reignite his passion for the kitchen -- and zest for life and love.', NULL, NULL, 3.6097, 7.113, 0, 1.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
