INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3241, 24816, 'tt0061715', NULL, 'The Gnome-Mobile', 'The Gnome-Mobile', 'movie', 1967, 'https://image.tmdb.org/t/p/w500/oeugD3jvHaNCaSc6r3NK1EcYvty.jpg', 'https://image.tmdb.org/t/p/original/sf3xfJppftP4VF0Ta2sqlT8oe2x.jpg', 'An eccentric millionaire and his grandchildren are embroiled in the plights of some forest gnomes who are searching for the rest of their tribe. While helping them, the millionaire is suspected of being crazy because he''s seeing gnomes! He''s committed, and the niece and nephew and the gnomes have to find him and free him.', NULL, NULL, 1.2716, 6.254, 0, 9.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3242, 28367, 'tt0056700', NULL, 'The Wonderful World of the Brothers Grimm', 'The Wonderful World of the Brothers Grimm', 'movie', 1962, 'https://image.tmdb.org/t/p/w500/zElwCWdMG7A6xThgesRxNrgD2MP.jpg', 'https://image.tmdb.org/t/p/original/gUmxshmfbFC7zFBt9kwdkSdQCNy.jpg', 'The Grimm brothers Wilhelm and Jacob, known for their literary works in the nineteenth century, have their lives dramatized. Wilhelm fights to write something entertaining amongst the sea of dry, non-fiction books they write and he sets about collecting oral-tradition fairy tales to put into print. Their life story is countered with reenactments of three of their stories including "The Dancing Princess," "The Cobbler and the Elves" and "The Singing Bone."', NULL, NULL, 0.5175, 5.857, 0, 9.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3243, 18283, 'tt0046807', NULL, 'Brigadoon', 'Brigadoon', 'movie', 1954, 'https://image.tmdb.org/t/p/w500/va3DcpyZDnnWdRB0FTPKzObo3Uz.jpg', 'https://image.tmdb.org/t/p/original/eGzQPFy6VTR3r72mTOIOXoQYuHc.jpg', 'Americans Jeff and Tommy, hunting in Scotland, stumble upon a village - Brigadoon. They soon learn that the town appears once every 100 years in order to preserve its peace and special beauty. The citizens go to bed at night and when they wake up, it''s 100 years later. Tommy falls in love with a beautiful young woman, Fiona, and is torn between staying or going back to his hectic life in New York.', NULL, NULL, 0.3815, 6.5, 0, 9.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
