INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3249, 14578, 'tt0168361', NULL, 'The Adventures of Peter Pan', 'ピーターパンの冒険', 'tv', 1989, 'https://image.tmdb.org/t/p/w500/cPeTO5cvRdhgXCFCVo7wbn52qtn.jpg', 'https://image.tmdb.org/t/p/original/zsuG0VnUEwye5jng3tWRxZGP8wg.jpg', 'The anime starts with Wendy having a dream about Peter Pan rescuing her and having a sword fight with Captain Hook. Wendy and her two brothers later on the episode go to Never Never land and Wendy becomes the ''mother'' of the Lost boys. Throughout the series a romance blooms between Peter and Wendy as they go on fights with pirates . The last half of the series go to a different direction then the original story line and also introduce a new character ( Princess Luna ) who becomes an important part of the last episodes.', NULL, NULL, 3.202, 8.5, 0, 10.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
