INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3254, 43350, 'tt0046000', NULL, 'Lili', 'Lili', 'movie', 1953, 'https://image.tmdb.org/t/p/w500/3vcaVT09imU0XlxClUlgMAYMexu.jpg', 'https://image.tmdb.org/t/p/original/9sb3ZuRM7QM5ubaEk0cCJfv4JvN.jpg', 'Members of a circus troupe "adopt" Lili Daurier when she finds herself stranded in a strange town. The magician who first comes to her rescue already has romantic entanglements and thinks of her as a little girl. Who can she turn to but the puppets, singing to them her troubles, forgetting that there are puppeteers? A crowd gathers around Lili as she sings. The circus has a new act. She now has a job. Will she get her heart''s desire?', NULL, NULL, 0.5339, 6.766, 0, 9.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
