INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3256, 210758, NULL, NULL, 'Cinderella Again', 'Cinderella Again', 'tv', 2022, 'https://image.tmdb.org/t/p/w500/mTV1wSS9fP5Xuxo9OpAqiUADPg7.jpg', 'https://image.tmdb.org/t/p/original/AtAFpDbOIv8cOGnxwBSBDfyibfz.jpg', 'Shion Hagino is a 29-year-old beauty consultant. Although she has never had a boyfriend, Shion leads a happy and fulfilling life. However, one day, Shion participates in a blind date party and it triggers a flashback where she was rejected by her first love back in high school, who told her, "If you''re going to confess, you should at least do something about your appearance". As if drawn back by her past trauma, Shion somehow goes back in time and becomes a 17-year-old high school student again. Using the makeup techniques she has honed, Shion decides to move towards a different timeline as compared to what happened 12 years ago.', NULL, NULL, 1.503, 6.6, 0, 10.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
