INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3306, 390062, 'tt3758172', NULL, 'Jungle', 'Jungle', 'movie', 2017, 'https://image.tmdb.org/t/p/w500/tDgxknTVwrScxpCYyGUjXSn5NRk.jpg', 'https://image.tmdb.org/t/p/original/tav8VVa6H6KooK5rFhAG2jT5ZNx.jpg', 'In 1981, an enthusiastic young adventurer follows his dreams into the Bolivian Amazon jungle with two friends and a guide with a mysterious past. Their journey quickly turns into a terrifying ordeal as the darkest elements of human nature and the deadliest threats of the wilderness lead to an all-out fight for survival.', NULL, NULL, 3.5545, 6.658, 0, 1.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3307, 46845, 'tt0067388', NULL, 'Man in the Wilderness', 'Man in the Wilderness', 'movie', 1971, 'https://image.tmdb.org/t/p/w500/2thgsNTcJ9sz6viuUe6kcRFBlIG.jpg', 'https://image.tmdb.org/t/p/original/7AwsicUVwmol6VjhxVwdnAMrLw1.jpg', 'In the early 1800s, a group of fur trappers and Indian traders are returning with their goods to civilization and are making a desperate attempt to beat the oncoming winter. When guide Zachary Bass is injured in a bear attack, they decide he''s a goner and leave him behind to die. When he recovers instead, he swears revenge on them and tracks them and their paranoiac expedition leader down.', NULL, NULL, 0.6098, 6.255, 0, 1.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3308, 14342, 'tt0119053', NULL, 'Almost Heroes', 'Almost Heroes', 'movie', 1998, 'https://image.tmdb.org/t/p/w500/kwZoIxl1RlsM0utYGt04CM20Kk9.jpg', 'https://image.tmdb.org/t/p/original/4XQ79WawtQUQnsKeJQkDvtqZM3m.jpg', 'Two hapless explorers lead an ill-fated 1804 expedition through the Pacific Northwest in a hopeless, doomed effort to reach the Pacific Ocean before Lewis and Clark.', NULL, NULL, 0.6891, 5.425, 0, 1.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3309, 9433, 'tt0119051', NULL, 'The Edge', 'The Edge', 'movie', 1997, 'https://image.tmdb.org/t/p/w500/zplJqfuUyqzW0D4jX3W1afl0d7b.jpg', 'https://image.tmdb.org/t/p/original/yU3nJxP2vNy8OQdDsfV09elG4k9.jpg', 'The plane carrying wealthy Charles Morse crashes down in the Alaskan wilderness. Together with the two other passengers, photographer Robert and assistant Stephen, Charles devises a plan to help them reach civilization. However, his biggest obstacle might not be the elements, or even the Kodiak bear stalking them -- it could be Robert, whom Charles suspects is having an affair with his wife and would not mind seeing him dead.', NULL, NULL, 1.4222, 6.855, 0, 9.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3310, 244316, 'tt1694021', NULL, 'Into the Grizzly Maze', 'Into the Grizzly Maze', 'movie', 2015, 'https://image.tmdb.org/t/p/w500/i5GbFCeZ0fG5xb2ta6B3yNgzIM7.jpg', 'https://image.tmdb.org/t/p/original/ovFz5YVSVxlkHnroFP7b2Rxiz9H.jpg', 'Two estranged brothers reunite at their childhood home in the Alaskan wild. They set out on a two-day hike and are stalked by an unrelenting grizzly bear.', NULL, NULL, 1.6348, 5.413, 0, 1.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3311, 89704, 'tt1683876', NULL, 'Happy People: A Year in the Taiga', 'Happy People: A Year in the Taiga', 'movie', 2010, 'https://image.tmdb.org/t/p/w500/wSDdllenxdsPiMONxEQEBfiLvio.jpg', 'https://image.tmdb.org/t/p/original/mrTHVR9Xdygn1AZKHR4opLFjM6m.jpg', 'In the center of the story is the life of the indigenous people of the village Bakhtia at the river Yenisei in the Siberian Taiga. The camera follows the protagonists in the village over a period of a year. The natives, whose daily routines have barely changed over the last centuries, keep living their lives according to their own cultural traditions.', NULL, NULL, 0.5337, 7.273, 0, 1.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3312, 6878, 'tt0107131', NULL, 'Homeward Bound: The Incredible Journey', 'Homeward Bound: The Incredible Journey', 'movie', 1993, 'https://image.tmdb.org/t/p/w500/el6dJEpK97OJRQiQhuiSGk2jkV5.jpg', 'https://image.tmdb.org/t/p/original/xDwDhLtQnA7jK4f7DVkdeSvZnAp.jpg', 'Before the Seavers leave for a family vacation to San Francisco, they drop off their pets -- Chance, an adventurous American bulldog; Shadow, a wise golden retriever; and Sassy, a cautious cat -- at a friend''s ranch. But when the animals start to worry that they''ve been left for good, the three embark together on a treacherous and thrilling journey to find their way back home through the California wilderness.', NULL, NULL, 1.7544, 7.0, 0, 2.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3313, 47951, 'tt0097050', NULL, 'The Adventures of Milo and Otis', '子猫物語', 'movie', 1986, 'https://image.tmdb.org/t/p/w500/imHIqEfWRZuJ2vLow0UJ9aqjyEO.jpg', 'https://image.tmdb.org/t/p/original/j3BQMBBJI66nufbC6j54S2JCuE5.jpg', 'When Milo the cat and Otis the dog are separated, they each set off on an adventurous and often perilous quest across mountains, plains, and snow-covered lands to reunite with one another.', NULL, NULL, 0.6047, 6.5, 0, 1.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3314, 16790, 'tt0101455', NULL, 'Bingo', 'Bingo', 'movie', 1991, 'https://image.tmdb.org/t/p/w500/giooyb8azHrgbwqWUWCn7QhIBBS.jpg', 'https://image.tmdb.org/t/p/original/3dbysGhZ5tpzL8vXnVoLqVQxdZS.jpg', 'A dog named Bingo escapes a circus and befriends a young boy named Chuckie. When Chuckie’s family moves away and leaves Bingo behind, the brave canine sets off on a perilous cross-country trek to reunite with his friend, overcoming countless obstacles—including dangerous criminals and his own fear of fire.', NULL, NULL, 0.8533, 5.1, 0, 1.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3315, 10762, 'tt0364751', NULL, 'Without a Paddle', 'Without a Paddle', 'movie', 2004, 'https://image.tmdb.org/t/p/w500/bSQBfHDzyfzxrCLepjegVb5F8j8.jpg', 'https://image.tmdb.org/t/p/original/vEEEKiUJOXmOJXW7X8P3kCgsm9p.jpg', 'Three friends, whose lives have been drifting apart, reunite for the funeral of a fourth childhood friend. When looking through their childhood belongings, they discover a trunk which contained details on a quest their friend was attempting. It revealed that he was hot on the trail of the $200,000 that went missing with airplane hijacker D.B. Cooper in 1971. They decide to continue his journey, but do not understand the dangers they will soon encounter.', NULL, NULL, 1.1876, 5.641, 0, 1.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3316, 136315, 'tt14452776', NULL, 'The Bear', 'The Bear', 'tv', 2022, 'https://image.tmdb.org/t/p/w500/eKfVzzEazSIjJMrw9ADa2x8ksLz.jpg', 'https://image.tmdb.org/t/p/original/aJtG4txtmiRHwAAqENQHZvBs6kY.jpg', 'Carmy, a young fine-dining chef, comes home to Chicago to run his family sandwich shop. As he fights to transform the shop and himself, he works alongside a rough-around-the-edges crew that ultimately reveal themselves as his chosen family.', NULL, NULL, 37.965, 8.14, 0, 1.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3317, 62204, 'tt0082484', NULL, 'Quest for Fire', 'La Guerre du feu', 'movie', 1981, 'https://image.tmdb.org/t/p/w500/tyzW1M00xfHKNtmTlT6wJ3F4pNr.jpg', 'https://image.tmdb.org/t/p/original/5l3Xb2WQR0nXiVhbj5rAv0z4xsZ.jpg', 'In the prehistoric world, a Cro-Magnon tribe depends on an ever-burning source of fire, which eventually extinguishes. Lacking the knowledge to start a new fire, the tribe sends three warriors on a quest for more. With the tribe''s future at stake, the warriors make their way across a treacherous landscape full of hostile tribes and monstrous beasts. On their journey, they encounter Ika, a woman who has the knowledge they seek.', NULL, NULL, 2.1758, 7.034, 0, 1.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3318, 501, 'tt0427312', NULL, 'Grizzly Man', 'Grizzly Man', 'movie', 2005, 'https://image.tmdb.org/t/p/w500/zuZWpcuye25rpsiZ4XzsAvmLDHG.jpg', 'https://image.tmdb.org/t/p/original/hAlB9MaamrP1eDhGA4AkjSAPxAf.jpg', 'Follows the story of "Grizzly Man" Timothy Treadwell and what the thirteen summers in a National Park in Alaska were like in his attempt to protect the grizzly bears. The film is full of unique images and a look into the spirit of a man who sacrificed himself for nature.', NULL, NULL, 1.2317, 7.5, 0, 6.5, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3319, 501, 'tt0076984', NULL, 'Battlestar Galactica', 'Battlestar Galactica', 'tv', 1978, 'https://image.tmdb.org/t/p/w500/27jl4H9PauenZlmVBbOO1pr1lGf.jpg', 'https://image.tmdb.org/t/p/original/88sdvwvX91VOYqGJUY1XQO84XIb.jpg', 'When the 12 Colonies of Man are wiped out by a cybernetic race called the Cylons, Commander Adama and the crew of the battlestar Galactica lead a ragtag fleet of human survivors in search of a "mythical planet" called Earth.', NULL, NULL, 4.7805, 7.112, 0, 8.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3320, 655, 'tt0092455', NULL, 'Star Trek: The Next Generation', 'Star Trek: The Next Generation', 'tv', 1987, 'https://image.tmdb.org/t/p/w500/vkLzXddgUKH5VcpnYiRzpJFrZhz.jpg', 'https://image.tmdb.org/t/p/original/qmliLoo6GVheM2FihatlAXxCKyF.jpg', 'Follow the intergalactic adventures of Capt. Jean-Luc Picard and his loyal crew aboard the all-new USS Enterprise NCC-1701D, as they explore new worlds.', NULL, NULL, 24.706, 8.373, 0, 8.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3321, 4018, 'tt0096684', NULL, 'Quantum Leap', 'Quantum Leap', 'tv', 1989, 'https://image.tmdb.org/t/p/w500/ujIGP3e3V6kDQHRhjNYtUE3fHJi.jpg', 'https://image.tmdb.org/t/p/original/5TpptGoxVVght2n6oz8QJklmSTu.jpg', 'Theorizing that one could time travel within his own lifetime, Dr. Sam Beckett stepped into the Quantum Leap accelerator and vanished... He woke to find himself trapped in the past, facing mirror images that were not his own and driven by an unknown force to change history for the better. His only guide on this journey is Al, an observer from his own time, who appears in the form of a hologram that only Sam can see and hear. And so Dr. Beckett finds himself leaping from life to life, striving to put right what once went wrong and hoping each time that his next leap will be the leap home.', NULL, NULL, 14.3728, 8.013, 0, 8.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3322, 12751, 'tt0084978', NULL, 'Automan', 'Automan', 'tv', 1983, 'https://image.tmdb.org/t/p/w500/4dOlxvavpgpDyAFmLNIre1JmcCf.jpg', 'https://image.tmdb.org/t/p/original/zcBS6kukiRZOBJRQDCLE4dt17a4.jpg', 'Automan is an American science fiction superhero television series produced by Glen A. Larson. It aired for only 12 episodes on ABC between 1983 and 1984.', NULL, NULL, 1.9394, 7.815, 0, 8.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3323, 11884, 'tt0087597', NULL, 'The Last Starfighter', 'The Last Starfighter', 'movie', 1984, 'https://image.tmdb.org/t/p/w500/A7oAHTjtYnIEQjJs62IONRufooq.jpg', 'https://image.tmdb.org/t/p/original/tw0YQznBe0WdQrQDzQpshq0LOP1.jpg', 'Video game expert Alex Rogan finds himself transported to another planet after conquering the video game The Last Starfighter, only to find out it was just a test. He was recruited to join the team of best Starfighters to defend their world from the attack.', NULL, NULL, 1.8937, 6.6, 0, 11.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3324, 967, 'tt0054331', NULL, 'Spartacus', 'Spartacus', 'movie', 1960, 'https://image.tmdb.org/t/p/w500/r0Fgg1GyZgzokaiw2HFQv3oPaL2.jpg', 'https://image.tmdb.org/t/p/original/9caD0fGCrp96JTFFeGyI0CGNj7.jpg', 'The rebellious Thracian Spartacus, born and raised a slave, is sold to Gladiator trainer Batiatus. After weeks of being trained to kill for the arena, Spartacus turns on his owners and leads the other slaves in rebellion. As the rebels move from town to town, their numbers swell as escaped slaves join their ranks. Under the leadership of Spartacus, they make their way to southern Italy, where they will cross the sea and return to their homes.', NULL, NULL, 2.3843, 7.538, 0, 10.5, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3325, 652, 'tt0332452', NULL, 'Troy', 'Troy', 'movie', 2004, 'https://image.tmdb.org/t/p/w500/a07wLy4ONfpsjnBqMwhlWTJTcm.jpg', 'https://image.tmdb.org/t/p/original/y51M7Ca95sCXTCDvJaRP1uzxKbg.jpg', 'In year 1250 B.C. during the late Bronze age, two emerging nations begin to clash. Paris, the Trojan prince, convinces Helen, Queen of Sparta, to leave her husband Menelaus, and sail with him back to Troy. After Menelaus finds out that his wife was taken by the Trojans, he asks his brother Agamemnon to help him get her back. Agamemnon sees this as an opportunity for power. They set off with 1,000 ships holding 50,000 Greeks to Troy.', NULL, NULL, 19.8373, 7.179, 0, 10.5, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
