INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3362, 1687999, NULL, NULL, 'TWICE IN A BLUE MOON (After Nokomis)', 'TWICE IN A BLUE MOON (After Nokomis)', 'movie', 2021, NULL, NULL, 'Twelve full moons were filmed consecutively each month for a year starting on the full Blue Moon of October 2020 and finishing on the full moon of 21 September 2021. Very fortunately I recorded 2 Blue Moons over the 12 months. The second part of the title refers to "Nokomis" meaning "Grandmother" to the Native North American language of the Ojibwe or Ainishinaabe people and made famous by the Longfellow''s poem "The Song of Hiawatha". The full moon names are those given them by the Native North Americans.', NULL, NULL, 0.1251, 0.0, 0, 1.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
