INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3447, 395797, 'tt3924782', NULL, 'The Horde', 'The Horde', 'movie', 2016, 'https://image.tmdb.org/t/p/w500/mHjXFWi5WnW2idcsOUC0zfAXvQd.jpg', 'https://image.tmdb.org/t/p/original/rhATinMhgKwBxsuS5OcFaaCSuuB.jpg', 'The film follows John Crenshaw as he accompanies his girlfriend and her students on a weekend nature-photography expedition deep into the woods. What should be an educational and fun-filled weekend turns into horror as the group is besieged by an unspeakable evil - a horde of hideously disfigured, mutated humans with an insatiable taste for blood. As things go from bad to worse, Crenshaw becomes their only hope if they are going to get out alive.', NULL, NULL, 1.2276, 4.873, 0, 10.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
