INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3449, 1089, 'tt0102685', NULL, 'Point Break', 'Point Break', 'movie', 1991, 'https://image.tmdb.org/t/p/w500/tlbERIghrQ4oofqlbF7H0K0EYnx.jpg', 'https://image.tmdb.org/t/p/original/yGOHbICOQwlJ20UjK8F2ChGJjvl.jpg', 'In Los Angeles, a gang of bank robbers who call themselves The Ex-Presidents commit their crimes while wearing masks of Reagan, Carter, Nixon and Johnson. Believing that the members of the gang could be surfers, the F.B.I. sends young agent Johnny Utah to the beach undercover to mix with the surfers and gather information.', NULL, NULL, 4.5158, 7.152, 0, 12.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3450, 9408, 'tt0423294', NULL, 'Surf''s Up', 'Surf''s Up', 'movie', 2007, 'https://image.tmdb.org/t/p/w500/kAeZfUDmuhnL8pLnxxFxBhYVdm6.jpg', 'https://image.tmdb.org/t/p/original/Y50RfoNVKIj9dSJavE8uBdN377.jpg', 'With a documentary crew in tow, Cody Maverick—a young surfer from Antarctica—travels to the pacific for his first professional competition. Determined to earn respect and live up to his idol, Big Z, Cody pushes himself to the limit. But all that changes when an encounter with a laid-back local forces him to rethink his values.', NULL, NULL, 2.5852, 6.512, 0, 11.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3451, 9266, 'tt0300532', NULL, 'Blue Crush', 'Blue Crush', 'movie', 2002, 'https://image.tmdb.org/t/p/w500/iZSw0JVG0cIFuZoTHuQU3nmGT4k.jpg', 'https://image.tmdb.org/t/p/original/xsVMKdSndUKid3Xm3Tudf5bcOlv.jpg', 'Nothing gets between Anne Marie and her board. Living in a beach shack with three roommates, she is up before dawn every morning to conquer the waves and count the days until the Pipe Masters competition. Having transplanted herself to Hawaii with no one''s blessing but her own, Anne Marie finds all she needs in the adrenaline-charged surf scene - until pro quarterback Matt Tollman comes along...', NULL, NULL, 0.9935, 5.998, 0, 12.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3452, 52886, 'tt0092732', NULL, 'Castaway', 'Castaway', 'movie', 1986, 'https://image.tmdb.org/t/p/w500/mphJksO1hwAEmcMawNFvRZJJ5n.jpg', 'https://image.tmdb.org/t/p/original/bpBcgPYG3PRjzxdBCuli8jeEslw.jpg', 'Middle-aged Gerald Kingsland advertises in a London paper for a female companion to spend a year with him on a desert island. Young Lucy Irving takes a chance on contacting him, but once on the island, things prove a lot less idyllic than in the movies. Gradually, it becomes clear that it is Lucy who has the desire and the strength to try and see the year through.', NULL, NULL, 1.2619, 6.28, 0, 11.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
