INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3454, 21, 'tt0060371', NULL, 'The Endless Summer', 'The Endless Summer', 'movie', 1966, 'https://image.tmdb.org/t/p/w500/jDdntrv2j64KB0Zpr63cko4Mebt.jpg', 'https://image.tmdb.org/t/p/original/uNRfK14Ga8Hwfqt07vo8nvWQN1i.jpg', 'Bruce Brown''s The Endless Summer is one of the first and most influential surf movies of all time. The film documents American surfers Mike Hynson and Robert August as they travel the world during California’s winter (which, back in 1965 was off-season for surfing) in search of the perfect wave and ultimately, an endless summer.', NULL, NULL, 0.3566, 7.163, 0, 11.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3455, 177888, 'tt2325989', NULL, 'Teen Beach Movie', 'Teen Beach Movie', 'movie', 2013, 'https://image.tmdb.org/t/p/w500/sKrGe5EmDSyVaWM0uj7rJDQHRjB.jpg', 'https://image.tmdb.org/t/p/original/uKoJTTgpyWiu04hzSgPWbyJfjYi.jpg', 'Life''s a beach for surfers Brady and McKenzie – until a rogue wave magically transports them inside the classic ''60s beach party flick, "Wet Side Story," where a full-blown rivalry between bikers and surfers threatens to erupt. There, amidst a sea of surfing, singing and dancing, Brady and Mack accidentally change the storyline, and the film’s dreamy hero and heroine fall for them instead of for each other!', NULL, NULL, 2.3424, 6.906, 0, 11.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
