INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3457, 43096, 'tt0052847', NULL, 'Gidget', 'Gidget', 'movie', 1959, 'https://image.tmdb.org/t/p/w500/i4aRCd5sRzYLb3TLm8iiUN0iJTr.jpg', 'https://image.tmdb.org/t/p/original/l1iQ1hkFYzKT2GyBIldCuJutYyM.jpg', 'Due to an accident while swimming in the sea, Francis meets the surfer Moondoggie. She''s fascinated with his sport and starts to hang out with his clique. Although they make fun of her at first, they teach her to surf and soon she''s accepted and given the nickname "Gidget". But it''s hard work to become more than a friend to Moondoggie.', NULL, NULL, 0.5556, 6.0, 0, 11.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3458, 14361, 'tt0103924', NULL, 'Captain Ron', 'Captain Ron', 'movie', 1992, 'https://image.tmdb.org/t/p/w500/otnKFXvqFH2swlrNf2sNiXpnIsR.jpg', 'https://image.tmdb.org/t/p/original/cUqa9ngoI72dFGVQKVLsTbzj65B.jpg', 'When mild-mannered Martin Harvey finds out that he has inherited a vintage yacht, he decides to take his family on a Caribbean vacation to retrieve the vessel. Upon arriving on a small island and realizing that the ship is in rough shape, Martin and his family end up with more than they bargained for as the roguish Captain Ron signs on to sail the boat to Miami. It doesn''t take long before Ron''s anything-goes antics get the Harveys into plenty of trouble.', NULL, NULL, 0.8389, 5.584, 0, 11.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3459, 884605, 'tt15671028', NULL, 'No Hard Feelings', 'No Hard Feelings', 'movie', 2023, 'https://image.tmdb.org/t/p/w500/gD72DhJ7NbfxvtxGiAzLaa0xaoj.jpg', 'https://image.tmdb.org/t/p/original/rRcNmiH55Tz0ugUsDUGmj8Bsa4V.jpg', 'On the brink of losing her childhood home, Maddie discovers an intriguing job listing: wealthy helicopter parents looking for someone to “date” their introverted 19-year-old son, Percy, before he leaves for college. To her surprise, Maddie soon discovers the awkward Percy is no sure thing.', NULL, NULL, 5.4836, 6.678, 0, 11.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3460, 8676, 'tt0770752', NULL, 'Fool''s Gold', 'Fool''s Gold', 'movie', 2008, 'https://image.tmdb.org/t/p/w500/f4djEBW3nyGRPLTcDlWYyaO43mx.jpg', 'https://image.tmdb.org/t/p/original/6vsZR4066s6ZbaAAqDdzDbC4kgH.jpg', 'Treasure hunter Ben "Finn" Finnegan has sunk his marriage to Tess and his trusty boat in his obsessive quest to find the legendary Queen''s Dowry. When he finds a vital clue that may finally pinpoint the treasure''s whereabouts, he drags Tess and her boss, billionaire Nigel Honeycutt, along on the hunt. But Finn is not the only one interested in the gold; his former mentor-turned-enemy Moe Fitch, hired by rapper-turned-gangster Bigg Bunny, will stop at nothing to beat him to it.', NULL, NULL, 2.1483, 5.792, 0, 11.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
