INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3462, 9870, 'tt0800039', NULL, 'Forgetting Sarah Marshall', 'Forgetting Sarah Marshall', 'movie', 2008, 'https://image.tmdb.org/t/p/w500/d4elOzyhNWVlxpG7BwigrumkFTe.jpg', 'https://image.tmdb.org/t/p/original/s39aQY3dK1s6ARrUKP5yeq824nR.jpg', 'When actress Sarah Marshall dumps aspiring musician Peter Bretter for rock star Aldous Snow, Peter''s world comes crashing down. His best friend Brian suggests that Peter should get away from everything and to fly off to Hawaii to escape all his problems. After arriving in Hawaii and meeting the beautiful receptionist Rachel Jansen, Peter is shocked to see not only Aldous in Hawaii, but also Sarah.', NULL, NULL, 2.7993, 6.506, 0, 11.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
