INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3465, 368239, 'tt5199588', NULL, 'View from a Blue Moon', 'View from a Blue Moon', 'movie', 2015, 'https://image.tmdb.org/t/p/w500/phFWGV9VJwhE9ZEpS8bG4uli1od.jpg', 'https://image.tmdb.org/t/p/original/6MxCEaIClUJ962LMiu0yTzuZAB.jpg', 'From the dreamy blue perfection of the South Pacific to the darkest uncharted waters of Africa (and everywhere in between), John Florence faces a broad spectrum of emotions as he continues to seal his legacy as one of the most gifted surfers ever. And while the young Hawaiian is pulled in increasingly different directions, there is no form of pressure that will keep him from his ultimate goal — to redefine what is possible in the ocean.', NULL, NULL, 0.395, 6.7, 0, 11.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
