INSERT OR IGNORE INTO "recommendations" ("id", "tmdb_id", "imdb_id", "igdb_id", "title", "original_title", "media_type", "release_year", "poster_url", "backdrop_url", "overview", "external_url", "platforms", "popularity", "vote_average", "is_ambiguous", "evidence_score", "created_at", "updated_at") VALUES (3506, 10314, 'tt0160862', NULL, 'She''s All That', 'She''s All That', 'movie', 1999, 'https://image.tmdb.org/t/p/w500/a0pepZNFCjggc7Na9gEwbTI1f46.jpg', 'https://image.tmdb.org/t/p/original/oSY7vsYlScliVKomRNviGuWXykC.jpg', 'High school hotshot Zach Siler is the envy of his peers. But his popularity declines sharply when his cheerleader girlfriend, Taylor, leaves him for sleazy reality-television star Brock Hudson. Desperate to revive his fading reputation, Siler agrees to a seemingly impossible challenge. He has six weeks to gain the trust of nerdy outcast Laney Boggs -- and help her to become the school''s next prom queen.', NULL, NULL, 2.7982, 6.333, 0, 1.0, '2026-07-20 01:02:04', '2026-07-20 01:02:04');
