UPDATE "recommendations" SET "tmdb_id"=117488, "imdb_id"='tt11041332', "igdb_id"=NULL, "title"='Yellowjackets', "original_title"='Yellowjackets', "media_type"='tv', "release_year"=2021, "poster_url"='https://image.tmdb.org/t/p/w500/xRnGrn7Z7SC0KIBodocoU1QgDZF.jpg', "backdrop_url"='https://image.tmdb.org/t/p/original/ibFWJDWS8cTO6s2vZVd2uKDm8p.jpg', "overview"='This equal parts survival epic, psychological horror story and coming-of-age drama tells the saga of a team of wildly talented high school girls soccer players who become the (un)lucky survivors of a plane crash deep in the remote northern wilderness. The series chronicles their descent from a complicated but thriving team to savage clans, while also tracking the lives they’ve attempted to piece back together nearly 25 years later.', "external_url"=NULL, "platforms"=NULL, "popularity"=8.435, "vote_average"=7.445, "is_ambiguous"=0, "evidence_score"=7.01500000000000056e+00, "created_at"='2026-07-15 12:01:52', "updated_at"='2026-07-20 01:02:04' WHERE "id"=14;
