UPDATE "recommendations" SET "tmdb_id"=254375, "imdb_id"='tt1626146', "igdb_id"=NULL, "title"='Hector and the Search for Happiness', "original_title"='Hector and the Search for Happiness', "media_type"='movie', "release_year"=2014, "poster_url"='https://image.tmdb.org/t/p/w500/lymRg46xAt6s9ApWa9MBcgnzXAS.jpg', "backdrop_url"='https://image.tmdb.org/t/p/original/vujKrqkydYxLuFvdGjA5bDicupV.jpg', "overview"='Hector is a quirky psychiatrist who has become increasingly tired of his humdrum life. As he tells his girlfriend, Clara, he feels like a fraud: he hasn’t really tasted life, and yet he’s offering advice to patients who are just not getting any happier. So Hector decides to break out of his deluded and routine driven life. Armed with buckets of courage and child-like curiosity, he embarks on a global quest in hopes of uncovering the elusive secret formula for true happiness. And so begins a larger than life adventure with riotously funny results.', "external_url"=NULL, "platforms"=NULL, "popularity"=1.679, "vote_average"=6.684, "is_ambiguous"=0, "evidence_score"=6.505, "created_at"='2026-07-15 12:01:52', "updated_at"='2026-07-20 01:02:04' WHERE "id"=173;
