UPDATE "recommendations" SET "tmdb_id"=68724, "imdb_id"='tt1535108', "igdb_id"=NULL, "title"='Elysium', "original_title"='Elysium', "media_type"='movie', "release_year"=2013, "poster_url"='https://image.tmdb.org/t/p/w500/aRjuJuPXHtVs6YegfeeQWXGRs1E.jpg', "backdrop_url"='https://image.tmdb.org/t/p/original/oo9GyiNKvR4CU1etuYl081UJ1LE.jpg', "overview"='In the year 2159, two classes of people exist: the very wealthy who live on a pristine man-made space station called Elysium, and the rest, who live on an overpopulated, ruined Earth. Secretary Rhodes, a hard line government official, will stop at nothing to enforce anti-immigration laws and preserve the luxurious lifestyle of the citizens of Elysium. That doesn’t stop the people of Earth from trying to get in, by any means they can. When unlucky Max is backed into a corner, he agrees to take on a daunting mission that, if successful, will not only save his life, but could bring equality to these polarized worlds.', "external_url"=NULL, "platforms"=NULL, "popularity"=5.9782, "vote_average"=6.523, "is_ambiguous"=0, "evidence_score"=10.11, "created_at"='2026-07-15 12:01:52', "updated_at"='2026-07-20 01:02:04' WHERE "id"=177;
