UPDATE "recommendations" SET "tmdb_id"=17654, "imdb_id"='tt1136608', "igdb_id"=NULL, "title"='District 9', "original_title"='District 9', "media_type"='movie', "release_year"=2009, "poster_url"='https://image.tmdb.org/t/p/w500/tuGlQkqLxnodDSk6mp5c2wvxUEd.jpg', "backdrop_url"='https://image.tmdb.org/t/p/original/jhM3wgWUrrOkz9r4xwV5cV5RhI4.jpg', "overview"='Thirty years ago, aliens arrive on Earth. Not to conquer or give aid, but to find refuge from their dying planet. Separated from humans in a South African area called District 9, the aliens are managed by Multi-National United, which is unconcerned with the aliens'' welfare but will do anything to master their advanced technology. When a company field agent contracts a mysterious virus that begins to alter his DNA, there is only one place he can hide: District 9.', "external_url"=NULL, "platforms"=NULL, "popularity"=4.5679, "vote_average"=7.474, "is_ambiguous"=0, "evidence_score"=1.97445454545454524e+01, "created_at"='2026-07-15 12:01:52', "updated_at"='2026-07-20 01:02:04' WHERE "id"=1176;
