UPDATE "recommendations" SET "tmdb_id"=8066, "imdb_id"='tt0371257', "igdb_id"=NULL, "title"='Stay', "original_title"='Stay', "media_type"='movie', "release_year"=2005, "poster_url"='https://image.tmdb.org/t/p/w500/nrLZVP8jG0KBcabahRPp6UP7Oy2.jpg', "backdrop_url"='https://image.tmdb.org/t/p/original/eUNQJ0XKHoGDDQzj1Y4WhE5zAFJ.jpg', "overview"='Psychiatrist Sam Foster has a new patient, Henry Letham, who claims to be suicidal. In trying to diagnose him, Sam visits Henry''s prior therapist and also finds Henry''s mother -- even though Henry has said that he murdered both of his parents. As reality starts to contradict fact, Sam spirals into an unstable mental state. Then he finds a clue as to how and when Henry may try to kill himself, and races to try to stop him.', "external_url"=NULL, "platforms"=NULL, "popularity"=1.7783, "vote_average"=6.632, "is_ambiguous"=0, "evidence_score"=11.515, "created_at"='2026-07-15 12:01:52', "updated_at"='2026-07-20 01:02:04' WHERE "id"=1446;
UPDATE "recommendations" SET "tmdb_id"=3558, "imdb_id"='tt0172493', "igdb_id"=NULL, "title"='Girl, Interrupted', "original_title"='Girl, Interrupted', "media_type"='movie', "release_year"=1999, "poster_url"='https://image.tmdb.org/t/p/w500/dOBdatHIVppvmRFw2z7bf9VKJr9.jpg', "backdrop_url"='https://image.tmdb.org/t/p/original/jDePFWhpfkY4GJm41qiRffJ0NGq.jpg', "overview"='Set in the changing world of the late 1960s, Susanna Kaysen''s prescribed "short rest" from a psychiatrist she had met only once becomes a strange, unknown journey into Alice''s Wonderland, where she struggles with the thin line between normal and crazy. Susanna soon realizes how hard it is to get out once she has been committed, and she ultimately has to choose between the world of people who belong inside or the difficult world of reality outside.', "external_url"=NULL, "platforms"=NULL, "popularity"=3.7722, "vote_average"=7.561, "is_ambiguous"=0, "evidence_score"=1.42116666666666677e+01, "created_at"='2026-07-15 12:01:52', "updated_at"='2026-07-20 01:02:04' WHERE "id"=1448;
UPDATE "recommendations" SET "tmdb_id"=50837, "imdb_id"='tt1441326', "igdb_id"=NULL, "title"='Martha Marcy May Marlene', "original_title"='Martha Marcy May Marlene', "media_type"='movie', "release_year"=2011, "poster_url"='https://image.tmdb.org/t/p/w500/bgB4sa9UfCyGdamfKAZXyEWuAwR.jpg', "backdrop_url"='https://image.tmdb.org/t/p/original/eN60BXsEWxFfgatPpYbGMVO5qdM.jpg', "overview"='After several years of living with a cult, Martha finally escapes and calls her estranged sister, Lucy, for help. Martha finds herself at the quiet Connecticut home Lucy shares with her new husband, Ted, but the memories of what she experienced in the cult make peace hard to find. As flashbacks continue to torment her, Martha fails to shake a terrible sense of dread, especially in regard to the cult''s manipulative leader.', "external_url"=NULL, "platforms"=NULL, "popularity"=2.8174, "vote_average"=6.572, "is_ambiguous"=0, "evidence_score"=7.01, "created_at"='2026-07-15 12:01:52', "updated_at"='2026-07-20 01:02:04' WHERE "id"=1449;
UPDATE "recommendations" SET "tmdb_id"=15058, "imdb_id"='tt0378793', "igdb_id"=NULL, "title"='Speak', "original_title"='Speak', "media_type"='movie', "release_year"=2004, "poster_url"='https://image.tmdb.org/t/p/w500/oRjQJG2PziTl2bUvzUCFS16ncfj.jpg', "backdrop_url"='https://image.tmdb.org/t/p/original/9J759jTIcQhmeeiD5bDuXI7iOoC.jpg', "overview"='Freshman high-school student Melinda has refused to speak ever since she called the cops on a popular summer party. With her old friends snubbing her for being a rat, and her parents too busy to notice her troubles, she folds into herself, trying to hide her secret: that star senior Andy raped her at the party. But Melinda does manage to find solace in her art class headed by Mr. Freeman.', "external_url"=NULL, "platforms"=NULL, "popularity"=1.54, "vote_average"=7.073, "is_ambiguous"=0, "evidence_score"=1.1504999999999999e+01, "created_at"='2026-07-15 12:01:52', "updated_at"='2026-07-20 01:02:04' WHERE "id"=1456;
UPDATE "recommendations" SET "tmdb_id"=6519, "imdb_id"='tt0377818', "igdb_id"=NULL, "title"='The Dukes of Hazzard', "original_title"='The Dukes of Hazzard', "media_type"='movie', "release_year"=2005, "poster_url"='https://image.tmdb.org/t/p/w500/2ZrNyYJEgE0VIqhelQPqFTR20xF.jpg', "backdrop_url"='https://image.tmdb.org/t/p/original/luOLydz3H319kUl79MbBcfGsCgz.jpg', "overview"='Cousins, Bo and Luke Duke, with the help of their eye-catching cousin, Daisy and moonshine-running Uncle Jesse, try and save the family farm from being destroyed by Hazzard County''s corrupt commissioner, Boss Hogg. Their efforts constantly find the ''Duke Boys'' eluding authorities in ''The General Lee'', their 1969 orange Dodge Charger that keeps them one step ahead of the dimwitted antics of the small southern town''s Sheriff, Roscoe P. Coltrane.', "external_url"=NULL, "platforms"=NULL, "popularity"=1.8955, "vote_average"=5.62, "is_ambiguous"=0, "evidence_score"=9.67666666666666586e+00, "created_at"='2026-07-15 12:01:52', "updated_at"='2026-07-20 01:02:04' WHERE "id"=1475;
UPDATE "recommendations" SET "tmdb_id"=95, "imdb_id"='tt0120591', "igdb_id"=NULL, "title"='Armageddon', "original_title"='Armageddon', "media_type"='movie', "release_year"=1998, "poster_url"='https://image.tmdb.org/t/p/w500/eTM3qtGhDU8cvjpoa6KEt5E2auU.jpg', "backdrop_url"='https://image.tmdb.org/t/p/original/1cO6OQJxz7YhTZ4V1OlkYfebeJa.jpg', "overview"='When an asteroid threatens to collide with Earth, NASA honcho Dan Truman determines the only way to stop it is to drill into its surface and detonate a nuclear bomb. This leads him to renowned driller Harry Stamper, who agrees to helm the dangerous space mission provided he can bring along his own hotshot crew. Among them is the cocksure A.J. who Harry thinks isn''t good enough for his daughter, until the mission proves otherwise.', "external_url"=NULL, "platforms"=NULL, "popularity"=5.9258, "vote_average"=6.834, "is_ambiguous"=0, "evidence_score"=12.01, "created_at"='2026-07-15 12:01:52', "updated_at"='2026-07-20 01:02:04' WHERE "id"=1476;
