UPDATE "recommendations" SET "tmdb_id"=895, "imdb_id"='tt0060107', "igdb_id"=NULL, "title"='Andrei Rublev', "original_title"='Андрей Рублёв', "media_type"='movie', "release_year"=1966, "poster_url"='https://image.tmdb.org/t/p/w500/jUihkn16SwPPIjuOyo6orHWUep6.jpg', "backdrop_url"='https://image.tmdb.org/t/p/original/jqha8JCXm0aJ5SJ03Jd0JmGgWRs.jpg', "overview"='An expansive Russian drama, this film focuses on the life of revered religious icon painter Andrei Rublev. Drifting from place to place in a tumultuous era, the peace-seeking monk eventually gains a reputation for his art. But after Rublev witnesses a brutal battle and unintentionally becomes involved, he takes a vow of silence and spends time away from his work. As he begins to ease his troubled soul, he takes steps towards becoming a painter once again.', "external_url"=NULL, "platforms"=NULL, "popularity"=1.5762, "vote_average"=7.942, "is_ambiguous"=0, "evidence_score"=7.005, "created_at"='2026-07-15 12:01:52', "updated_at"='2026-07-20 01:02:04' WHERE "id"=1860;
UPDATE "recommendations" SET "tmdb_id"=62177, "imdb_id"='tt1217209', "igdb_id"=NULL, "title"='Brave', "original_title"='Brave', "media_type"='movie', "release_year"=2012, "poster_url"='https://image.tmdb.org/t/p/w500/1XAuDtMWpL0sYSFK0R6EZate2Ux.jpg', "backdrop_url"='https://image.tmdb.org/t/p/original/qx9ts2hBYJrkIQxhryitxnLlm2u.jpg', "overview"='In the mystical Scottish Highlands, Merida is the princess of a kingdom ruled by King Fergus and Queen Elinor. An unruly daughter and an accomplished archer, Merida one day defies a sacred custom of the land and inadvertently brings turmoil to the kingdom. In an attempt to set things right, Merida seeks out an eccentric old Wise Woman and is granted an ill-fated wish. Also figuring into Merida''s quest — and serving as comic relief — are the kingdom''s three lords: the enormous Lord MacGuffin, the surly Lord Macintosh, and the disagreeable Lord Dingwall.', "external_url"=NULL, "platforms"=NULL, "popularity"=14.2731, "vote_average"=7.032, "is_ambiguous"=0, "evidence_score"=7.005, "created_at"='2026-07-15 12:01:52', "updated_at"='2026-07-20 01:02:04' WHERE "id"=1862;
