UPDATE "recommendations" SET "tmdb_id"=8814, "imdb_id"='tt0419706', "igdb_id"=NULL, "title"='Doom', "original_title"='Doom', "media_type"='movie', "release_year"=2005, "poster_url"='https://image.tmdb.org/t/p/w500/y50lH061yWOvEstoZRn7lYs0huk.jpg', "backdrop_url"='https://image.tmdb.org/t/p/original/9EpgaLS44zlXoTSAOhGiJmkIA4B.jpg', "overview"='A team of space marines known as the Rapid Response Tactical Squad, led by Sarge, is sent to a science facility on Mars after somebody reports a security breach. There, they learn that the alert came after a test subject, a mass murderer purposefully injected with alien DNA, broke free and began killing people. Dr. Grimm, who is related to team member Reaper, informs them all that the chromosome can mutate humans into monsters -- and is highly infectious.', "external_url"=NULL, "platforms"=NULL, "popularity"=2.3172, "vote_average"=5.197, "is_ambiguous"=0, "evidence_score"=1.0004999999999999e+01, "created_at"='2026-07-15 12:01:52', "updated_at"='2026-07-20 01:02:04' WHERE "id"=1926;
