UPDATE "recommendations" SET "tmdb_id"=1140619, "imdb_id"='tt29383405', "igdb_id"=NULL, "title"='Handmade - A Tale of Stop-motion', "original_title"='Handmade - A Tale of Stop-motion', "media_type"='movie', "release_year"=2023, "poster_url"='https://image.tmdb.org/t/p/w500/aLRfzBNNF5pMRSKKlgnyiIRNiIW.jpg', "backdrop_url"='https://image.tmdb.org/t/p/original/5iz7hpm502eC8v5X36UrCGp9DKh.jpg', "overview"='A documentary about an old animation technique and the film studio that tries to carry on the legacy. The worlds oldest animation studio still making film with stop motion technique is Nukufilm located in Tallinn, Estland. Here we can follow the work in the studio which was founded in the Soviet era and has survived heavy censorship and global competition.', "external_url"=NULL, "platforms"=NULL, "popularity"=0.0573, "vote_average"=10.0, "is_ambiguous"=0, "evidence_score"=11.02, "created_at"='2026-07-15 12:01:52', "updated_at"='2026-07-20 01:02:04' WHERE "id"=1939;
