UPDATE "recommendations" SET "tmdb_id"=2907, "imdb_id"='tt0101272', "igdb_id"=NULL, "title"='The Addams Family', "original_title"='The Addams Family', "media_type"='movie', "release_year"=1991, "poster_url"='https://image.tmdb.org/t/p/w500/qFf8anju5f2epI0my8RdwwIXFIP.jpg', "backdrop_url"='https://image.tmdb.org/t/p/original/7OxGhxUYAdtuike29VMzEFxJx7y.jpg', "overview"='When a man claiming to be long-lost Uncle Fester reappears after 25 years lost, the family plans a celebration to wake the dead. But the kids barely have time to warm up the electric chair before Morticia begins to suspect Fester is fraud when he can''t recall any of the details of Fester''s life.', "external_url"=NULL, "platforms"=NULL, "popularity"=4.3625, "vote_average"=7.073, "is_ambiguous"=0, "evidence_score"=9.825, "created_at"='2026-07-15 12:01:52', "updated_at"='2026-07-20 01:02:04' WHERE "id"=2121;
UPDATE "recommendations" SET "tmdb_id"=36819, "imdb_id"='tt0081633', "igdb_id"=NULL, "title"='Time Bandits', "original_title"='Time Bandits', "media_type"='movie', "release_year"=1981, "poster_url"='https://image.tmdb.org/t/p/w500/4VZtpwdhHQSa4LUkvujyGAHb1hG.jpg', "backdrop_url"='https://image.tmdb.org/t/p/original/qKERrt3UU1ml8Q9zdsLPpoQ5r3.jpg', "overview"='Young history buff Kevin can scarcely believe it when six dwarfs emerge from his closet one night. Former employees of the Supreme Being, they''ve purloined a map charting all of the holes in the fabric of time and are using it to steal treasures from different historical eras. Taking Kevin with them, they variously drop in on Napoleon, Robin Hood and King Agamemnon before the Supreme Being catches up with them.', "external_url"=NULL, "platforms"=NULL, "popularity"=1.3913, "vote_average"=6.623, "is_ambiguous"=0, "evidence_score"=11.0225, "created_at"='2026-07-15 12:01:52', "updated_at"='2026-07-20 01:02:04' WHERE "id"=2131;
