UPDATE "recommendations" SET "tmdb_id"=82682, "imdb_id"='tt1321870', "igdb_id"=NULL, "title"='Gangster Squad', "original_title"='Gangster Squad', "media_type"='movie', "release_year"=2013, "poster_url"='https://image.tmdb.org/t/p/w500/wAuQNTBFBu2yXZsX6yLhUPiwTlW.jpg', "backdrop_url"='https://image.tmdb.org/t/p/original/cdd4S09XxLLvp6IRN4PQamPAXL6.jpg', "overview"='Los Angeles, 1949. Ruthless, Brooklyn-born mob king Mickey Cohen runs the show in this town, reaping the ill-gotten gains from the drugs, the guns, the prostitutes and — if he has his way — every wire bet placed west of Chicago. And he does it all with the protection of not only his own paid goons, but also the police and the politicians who are under his control. It’s enough to intimidate even the bravest, street-hardened cop… except, perhaps, for the small, secret crew of LAPD outsiders led by Sgt. John O’Mara and Jerry Wooters who come together to try to tear Cohen’s world apart.', "external_url"=NULL, "platforms"=NULL, "popularity"=3.1122, "vote_average"=6.381, "is_ambiguous"=0, "evidence_score"=6.505, "created_at"='2026-07-15 12:01:52', "updated_at"='2026-07-20 01:02:04' WHERE "id"=2355;
