UPDATE "recommendations" SET "tmdb_id"=8358, "imdb_id"='tt0162222', "igdb_id"=NULL, "title"='Cast Away', "original_title"='Cast Away', "media_type"='movie', "release_year"=2000, "poster_url"='https://image.tmdb.org/t/p/w500/7lLJgKnAicAcR5UEuo8xhSMj18w.jpg', "backdrop_url"='https://image.tmdb.org/t/p/original/oCFVYPXI4IfhtF3GapU2jkDicDI.jpg', "overview"='Chuck Noland, a top international manager for FedEx, and Kelly, a Ph.D. student, are in love and heading towards marriage. Then Chuck''s plane to Malaysia crashes at sea during a terrible storm. He''s the only survivor, and finds himself marooned on a desolate island. With no way to escape, Chuck must find ways to survive in his new home.', "external_url"=NULL, "platforms"=NULL, "popularity"=6.6881, "vote_average"=7.7, "is_ambiguous"=0, "evidence_score"=14.538, "created_at"='2026-07-15 12:01:52', "updated_at"='2026-07-20 01:02:04' WHERE "id"=2486;
UPDATE "recommendations" SET "tmdb_id"=421, "imdb_id"='tt0362270', "igdb_id"=NULL, "title"='The Life Aquatic with Steve Zissou', "original_title"='The Life Aquatic with Steve Zissou', "media_type"='movie', "release_year"=2004, "poster_url"='https://image.tmdb.org/t/p/w500/qZoFLNBC78jzboWeDH6Ha0qavF2.jpg', "backdrop_url"='https://image.tmdb.org/t/p/original/7tWktnLQ81G8pHUkhuTebcTkcB3.jpg', "overview"='Renowned oceanographer Steve Zissou has sworn vengeance upon the rare shark that devoured a member of his crew. In addition to his regular team, he is joined on his boat by Ned, a man who believes Zissou to be his father, and Jane, a journalist pregnant by a married man. They travel the sea, all too often running into pirates and, perhaps more traumatically, various figures from Zissou''s past, including his estranged wife, Eleanor.', "external_url"=NULL, "platforms"=NULL, "popularity"=1.8679, "vote_average"=7.075, "is_ambiguous"=0, "evidence_score"=9.01333333333333364e+00, "created_at"='2026-07-15 12:01:52', "updated_at"='2026-07-20 01:02:04' WHERE "id"=2491;
UPDATE "recommendations" SET "tmdb_id"=110416, "imdb_id"='tt1865505', "igdb_id"=NULL, "title"='Song of the Sea', "original_title"='Song of the Sea', "media_type"='movie', "release_year"=2014, "poster_url"='https://image.tmdb.org/t/p/w500/16LQC6zpqB0l74mVWb93a2oMFnX.jpg', "backdrop_url"='https://image.tmdb.org/t/p/original/mVLZvSe1Aa8CFKx0cInTamVZJrW.jpg', "overview"='The story of the last Seal Child’s journey home. After their mother’s disappearance, Ben and Saoirse are sent to live with Granny in the city. When they resolve to return to their home by the sea, their journey becomes a race against time as they are drawn into a world Ben knows only from his mother’s folktales. But this is no bedtime story; these fairy folk have been in our world far too long. It soon becomes clear to Ben that Saoirse is the key to their survival.', "external_url"=NULL, "platforms"=NULL, "popularity"=3.4822, "vote_average"=8.0, "is_ambiguous"=0, "evidence_score"=6.06000000000000049e+00, "created_at"='2026-07-15 12:01:52', "updated_at"='2026-07-20 01:02:04' WHERE "id"=2508;
