UPDATE "recommendations" SET "tmdb_id"=122906, "imdb_id"='tt2194499', "igdb_id"=NULL, "title"='About Time', "original_title"='About Time', "media_type"='movie', "release_year"=2013, "poster_url"='https://image.tmdb.org/t/p/w500/ls6zswrOZVhCXQBh96DlbnLBajM.jpg', "backdrop_url"='https://image.tmdb.org/t/p/original/einbto9qLXFx9QXxEHylaxDbKPx.jpg', "overview"='The night after another unsatisfactory New Year''s party, Tim''s father reveals to him that the men in their family have the ability to travel through time. They can''t change history, but they can change what happens and has happened in their own lives. Thus begins the start of a lesson in learning to appreciate life itself as it is, as it comes, and most importantly, the people living alongside us.', "external_url"=NULL, "platforms"=NULL, "popularity"=11.8919, "vote_average"=7.907, "is_ambiguous"=0, "evidence_score"=11.55, "created_at"='2026-07-15 12:01:52', "updated_at"='2026-07-20 01:02:04' WHERE "id"=2522;
